{
  "name": "Blank HTML Page",
  "description": "A simple, blank HTML page."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';

const App: React.FC = () => {
  return null; // Render nothing to keep the page blank
};

export default App;

    /* تنسيق خريطة الأسابيع (الجديد) */
.weeks-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr); /* 4 أعمدة */
    gap: 8px;
    background: rgba(0,0,0,0.3);
    padding: 10px;
    border-radius: 8px;
    border: 1px solid var(--border);
    margin-top: 10px;
}

.week-box {
    background: var(--bg-app);
    border: 1px solid #333;
    border-radius: 6px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 800;
    font-size: 0.8rem;
    color: var(--text-muted);
    position: relative;
}

/* الأسبوع الحالي (نابض) */
.week-box.active {
    border-color: var(--danger);
    color: #fff;
    background: rgba(255, 75, 75, 0.1);
    box-shadow: 0 0 10px rgba(255, 75, 75, 0.2);
    animation: pulseBorder 2s infinite;
}

/* الأسابيع المنتهية */
.week-box.done {
    background: #111;
    color: #444;
    text-decoration: line-through;
    border-color: #222;
}

@keyframes pulseBorder {
    0% { border-color: var(--danger); }
    50% { border-color: transparent; }
    100% { border-color: var(--danger); }
}

    /* --- Fix SweetAlert Z-Index --- */
/* اجبار نافذة الحذف للظهور فوق كل شيء */
.swal2-container {
    z-index: 10000 !important;
}

        /* --- 1. GAMIFIED THEME VARIABLES --- */
        :root {
            /* Core Colors */
            --bg-app: #131422;
            --bg-panel: #202136;
            --bg-dim: rgba(255,255,255,0.05);
            --border: #2d2f45;

            /* Typography */
            --text-main: #ffffff;
            --text-muted: #8b9bb4;

            /* UI Accents */
            --accent: #58cc02;        /* Success/Green */
            --accent-shadow: #46a302; 

            --danger: #ff4b4b;        /* Error/Combat/Red */
            --danger-shadow: #d42a2a;

            --warning: #ffc800;       /* Gold/Rare/Yellow */
            --warning-shadow: #e5b400;

            --inject: #ce82ff;        /* Magic/Skill/Purple */
            --inject-shadow: #a561d1;

            /* RPG Stat Colors */
            --stat-str: #ff9600;      /* Strength */
            --stat-dis: #2b70c9;      /* Discipline */
            --stat-int: #1cb0f7;      /* Intelligence */
            --stat-chr: #ff4b4b;      /* Charisma */
            --stat-emt: #ce82ff;      /* Emotional */
            --stat-pce: #89e219;      /* Peace */

            /* Dimensions */
            --radius-l: 16px;
            --radius-m: 12px;
            --radius-s: 8px;
        }

        /* Global Reset */
        * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; outline: none; }

        body { 
            margin: 0; 
            background-color: var(--bg-app); 
            color: var(--text-main); 
            font-family: "Nunito", "Segoe UI", Tahoma, sans-serif;
            height: 100vh; 
            display: flex; 
            flex-direction: column; 
            overflow: hidden; 
            direction: ltr; /*  is English-Left-to-Right based */
        }

        /* Animations */
        @keyframes popIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }

       /* في الـ CSS - ابحث عن .main-content وغيّرها: */
.main-content { 
    flex: 1; 
    overflow-y: auto; 
    padding: 85px 16px 95px 16px;
    -webkit-overflow-scrolling: touch; /* ✅ مهم للجوال */
}
        .page { 
            display: none; 
            animation: popIn 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
        }
        .page.active { display: block; }

        .hidden { display: none !important; }

        .section-title {
            font-size: 0.85rem; 
            color: var(--text-muted); 
            font-weight: 800;
            text-transform: uppercase; 
            letter-spacing: 1px; 
            margin: 25px 0 10px 0;
            padding-left: 10px; 
            border-left: 4px solid var(--border);
            display: flex; align-items: center; gap: 8px;
        }
        /* --- 2. COMPONENTS: BUTTONS & HUD --- */
        .status-bar {
            height: 70px; background: var(--bg-app); 
            border-bottom: 2px solid var(--border);
            display: flex; align-items: center; justify-content: space-between;
            padding: 0 16px; 
            position: fixed; top: 0; left: 0; width: 100%; z-index: 1000;
        }

        .hud-container { display: flex; gap: 8px; align-items: center; }

        .hud-badge {
            display: flex; align-items: center; gap: 6px;
            padding: 6px 10px; border-radius: var(--radius-m);
            font-weight: 800; font-size: 0.85rem;
            border-bottom: 3px solid rgba(0,0,0,0.2);
        }

        .hud-gold { background: var(--bg-panel); color: var(--warning); border: 1px solid var(--warning); }
        .hud-streak { background: var(--bg-panel); color: var(--danger); border: 1px solid var(--danger); }
        .hud-lvl { background: var(--bg-panel); color: var(--stat-int); border: 1px solid var(--stat-int); }

        .btn-3d {
            background-color: var(--inject); color: #fff; border: none;
            border-radius: var(--radius-m); padding: 8px 16px;
            font-weight: 800; font-size: 0.9rem; cursor: pointer;
            box-shadow: 0 4px 0 var(--inject-shadow); transition: all 0.1s;
            display: flex; align-items: center; justify-content: center; gap: 8px;
            text-transform: uppercase; letter-spacing: 0.5px;
        }
        /* ستايل الزر النشط (Cyberpunk Glow) */
        .btn-3d.active-mode {
            background-color: var(--stat-int) !important; /* لون سماوي كهربائي */
            color: #fff !important;
            border-color: #fff !important;
            box-shadow: 0 0 15px var(--stat-int), 0 0 5px #fff !important; /* توهج نيون */
            transform: translateY(2px); /* كأن الزر مضغوط */
        }
                /* --- Hacker Style for Code Input --- */
        .console-input {
            background-color: #000 !important;      /* خلفية سوداء تماماً */
            border-color: var(--accent) !important; /* إطار أخضر مشع */
            color: var(--accent) !important;        /* نص أخضر */
            font-family: 'Courier New', Courier, monospace; /* خط الكود الكلاسيكي */
            font-weight: bold;
        }

        /* تأثير توهج إضافي عند الكتابة داخله */
        .console-input:focus {
            box-shadow: 0 0 15px var(--accent-shadow) !important;
            outline: none;
        }

        /* تغيير لون النص التوضيحي (placeholder) ليكون أخضر باهت */
        .console-input::placeholder {
            color: rgba(88, 204, 2, 0.5) !important;
        }
        /* --- تصميم القوائم المنسدلة (Hacker Style) --- */
        select {
            background-color: #000 !important;      /* خلفية سوداء (Terminal) */
            color: #fff !important;                 /* نص أبيض */
            border: 1px solid var(--border) !important;
            border-radius: var(--radius-m) !important;
            padding: 14px !important;
            font-weight: 800 !important;
            font-family: 'Courier New', monospace;  /* خط الكود */
            cursor: pointer;
            outline: none;
            /* سهم مخصص بسيط */
            background-image: linear-gradient(45deg, transparent 50%, var(--accent) 50%),
                              linear-gradient(135deg, var(--accent) 50%, transparent 50%);
            background-position: calc(100% - 20px) calc(1em + 2px),
                                 calc(100% - 15px) calc(1em + 2px);
            background-size: 5px 5px,
                             5px 5px;
            background-repeat: no-repeat;
            appearance: none; /* إخفاء شكل النظام الافتراضي */
            -webkit-appearance: none;
        }

        /* عند التركيز (Focus) - توهج أخضر هكرز */
        select:focus {
            border-color: var(--accent) !important;
            box-shadow: 0 0 15px var(--accent-shadow) !important;
        }

        /* تنسيق الخيارات الداخلية (قد يختلف ظهوره حسب نوع الهاتف) */
        option {
            background-color: #111;
            color: #fff;
            padding: 10px;
        }

        /* --- تصميم القوائم المنسدلة (Dropdowns) --- */
        select {
            background-color: var(--bg-panel) !important; /* خلفية داكنة */
            color: #fff !important;                       /* نص أبيض */
            border: 2px solid var(--border) !important;   /* إطار خافت */
            border-radius: var(--radius-m) !important;
            padding: 14px !important;
            font-weight: 800 !important;
            cursor: pointer;
            appearance: none; /* إخفاء سهم المتصفح الافتراضي (اختياري) */
            background-image: url("data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23007CB2%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22%2F%3E%3C%2Fsvg%3E");
            background-repeat: no-repeat;
            background-position: right 15px top 50%;
            background-size: 12px auto;
        }

        /* عند التركيز (Focus) - توهج سماوي */
        select:focus {
            border-color: var(--stat-int) !important;
            box-shadow: 0 0 10px rgba(28, 176, 246, 0.4) !important;
            outline: none;
        }

        /* تنسيق الخيارات الداخلية */
        option {
            background-color: var(--bg-app);
            color: #fff;
            padding: 10px;
        }

        .btn-3d:active { transform: translateY(4px); box-shadow: 0 0 0 var(--inject-shadow); }
        .btn-3d.danger { background-color: var(--danger); box-shadow: 0 4px 0 var(--danger-shadow); }
        .btn-3d.success { background-color: var(--accent); box-shadow: 0 4px 0 var(--accent-shadow); }
        .btn-3d.neutral { background-color: var(--bg-panel); box-shadow: 0 4px 0 var(--border); border: 1px solid var(--border); color: var(--text-muted); }

        /* --- 3. CARDS & LISTS --- */
        .card {
            background: var(--bg-panel);
            border: 2px solid var(--border);
            border-radius: var(--radius-l);
            padding: 16px; margin-bottom: 16px;
        }

        .game-row {
            display: flex; justify-content: space-between; align-items: center;
            background: var(--bg-panel);
            border: 2px solid var(--border);
            border-bottom: 4px solid var(--border);
            border-radius: var(--radius-m);
            padding: 16px; margin-bottom: 12px;
            transition: transform 0.1s;
        }
        .game-row:active { transform: translateY(2px); border-bottom-width: 2px; }

        .meta-tag {
            font-size: 0.65rem; font-weight: 800;
            padding: 4px 8px; border-radius: 6px;
            text-transform: uppercase; margin-right: 5px;
            display: inline-block;
        }
        .tag-normal { background: rgba(28, 176, 246, 0.15); color: var(--stat-int); }
        .tag-big { background: rgba(255, 75, 75, 0.15); color: var(--danger); }
        .tag-skill { background: rgba(206, 130, 255, 0.15); color: var(--inject); border: 1px solid var(--inject); }

        /* --- 4. NEW FEATURES CSS (TROPHIES & SKILLS) --- */
        .trophy-grid {
            display: grid; grid-template-columns: repeat(auto-fill, minmax(70px, 1fr)); gap: 10px;
        }
        .trophy-item {
            background: var(--bg-app); border: 2px solid var(--border);
            border-radius: var(--radius-m); padding: 10px 5px;
            text-align: center; cursor: pointer; transition: all 0.2s;
        }
                /* السماح بالضغط على الأوسمة المقفلة */
        .trophy-item.locked { 
            filter: grayscale(100%); 
            opacity: 0.6; 
            cursor: pointer; /* كان pointer-events: none وهذا اللي يمنع الضغط */
            border-color: rgba(255,255,255,0.1);
        }

        .trophy-item.unlocked { border-color: var(--warning); background: rgba(255, 200, 0, 0.05); box-shadow: 0 4px 0 var(--warning-shadow); }

        /* Multi-Stat Checkbox */
        .stat-checkbox-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 8px; margin-bottom: 15px; }
        .stat-check-box { display: block; position: relative; cursor: pointer; }
        .stat-check-box input { position: absolute; opacity: 0; }
        .stat-checkmark {
            display: flex; align-items: center; justify-content: center;
            height: 40px; background-color: var(--bg-app);
            border: 2px solid var(--border); border-radius: var(--radius-s);
            color: var(--text-muted); font-weight: 800; font-size: 0.75rem; transition: 0.2s;
        }
        .stat-check-box input:checked ~ .stat-checkmark {
            border-color: var(--stat-int); color: var(--stat-int); background: rgba(28, 176, 246, 0.1);
        }

        /* --- 5. MODAL & FORMS --- */
        .modal {
            display: none; position: fixed; top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(19, 20, 34, 0.95); z-index: 2000;
            align-items: center; justify-content: center; backdrop-filter: blur(5px);
        }
        .modal.active { display: flex; }
        .modal-content {
            background: var(--bg-panel); border: 2px solid var(--border);
            width: 90%; max-width: 400px; padding: 24px;
            border-radius: var(--radius-l); box-shadow: 0 10px 40px rgba(0,0,0,0.5);
            max-height: 85vh; overflow-y: auto;
        }
        input, select, textarea {
            width: 100%; background: var(--bg-app); 
            border: 2px solid var(--border); border-radius: var(--radius-m);
            color: var(--text-main); padding: 14px; margin-bottom: 16px;
            font-family: inherit; font-weight: 700; font-size: 1rem;
        }
        input:focus, select:focus { border-color: var(--stat-int); border-bottom: 4px solid var(--stat-int); }

        /* --- 6. NAV & PROGRESS --- */
        .bottom-nav {
            position: fixed; bottom: 0; width: 100%; height: 80px;
            background: var(--bg-app); border-top: 2px solid var(--border);
            display: flex; justify-content: space-around; align-items: center;
            z-index: 100; padding-bottom: 15px;
        }
        .nav-item {
            display: flex; justify-content: center; align-items: center;
            width: 50px; height: 50px; border-radius: 16px;
            color: var(--text-muted); font-size: 1.5rem;
            cursor: pointer; transition: all 0.2s;
            border: 2px solid transparent; border-bottom: 4px solid transparent;
        }
        .nav-item.active {
            background: rgba(28, 176, 246, 0.15); color: var(--stat-int);
            border-color: rgba(28, 176, 246, 0.3); border-bottom-width: 4px;
        }
        .progress-container { height: 10px; background: var(--bg-app); border-radius: 5px; overflow: hidden; margin-top: 8px; }
        .progress-fill { height: 100%; transition: width 0.5s ease; border-radius: 5px; }
        /* --- 7. TOAST NOTIFICATIONS (تنبيهات احترافية) --- */
        .toast-box {
            position: fixed; bottom: 100px; left: 50%; transform: translateX(-50%);
            z-index: 3000; display: flex; flex-direction: column; gap: 8px;
            pointer-events: none; width: 90%; max-width: 300px;
        }
        .toast {
            background: rgba(32, 33, 54, 0.95); backdrop-filter: blur(5px);
            border: 1px solid var(--border); border-left: 4px solid var(--text-muted);
            padding: 12px 16px; border-radius: var(--radius-m);
            color: #fff; font-size: 0.9rem; font-weight: 700;
            box-shadow: 0 5px 15px rgba(0,0,0,0.3);
            display: flex; align-items: center; gap: 10px;
            animation: slideUp 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .toast.success { border-left-color: var(--accent); }
        .toast.danger { border-left-color: var(--danger); }
        .toast.gold { border-left-color: var(--warning); color: var(--warning); }
                /* --- Streak Modal Styles --- */
        .circle-container {
            display: flex; justify-content: center; align-items: center; margin: 20px 0;
        }

        /* الدائرة الخلفية والمتحركة (تعتمد على conic-gradient) */
        .circular-progress {
            position: relative;
            height: 160px; width: 160px;
            border-radius: 50%;
            background: conic-gradient(var(--accent) 0deg, #222 0deg); /* سيتم تحديثها بالـ JS */
            display: flex; align-items: center; justify-content: center;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            transition: background 0.5s ease;
        }

        .circular-progress::before {
            content: ""; position: absolute;
            height: 140px; width: 140px;
            border-radius: 50%;
            background-color: #000; /* لون قلب الدائرة */
        }

        .inner-circle { position: relative; z-index: 2; }

        /* أزرار الأوضاع */
        .btn-mode {
            background: transparent; border: 1px solid var(--text-muted); color: var(--text-muted);
            padding: 5px 15px; border-radius: 20px; font-size: 0.7rem; font-weight: bold; cursor: pointer;
        }
        .btn-mode.active {
            background: var(--accent); color: #000; border-color: var(--accent);
            box-shadow: 0 0 10px var(--accent-shadow);
        }

        /* حالة الدرع الفعال */
        .shield-active {
            border-color: var(--stat-int) !important;
            box-shadow: 0 0 10px rgba(0, 200, 255, 0.2);
        }
        .shield-active #shield-icon { filter: none !important; }


