        document.getElementById('edit-real-id').value = item.id;
        document.getElementById('edit-real-type').value = type;
        document.getElementById('edit-title').value = item.title;
        document.getElementById('edit-desc').value = item.desc || "";
        document.querySelectorAll('.edit-stat-chk').forEach(cb => cb.checked = false);
        if (item.stats) {
            item.stats.forEach(s => {
                const cb = document.querySelector(`.edit-stat-chk[value="${s}"]`);
                if (cb) cb.checked = true;
            });
        }
        document.getElementById('modal-edit-only').classList.add('active');
    },

    saveEdit: () => {
        const id = document.getElementById('edit-real-id').value;
        const type = document.getElementById('edit-real-type').value;
        const newTitle = document.getElementById('edit-title').value.trim();
        const newDesc = document.getElementById('edit-desc').value.trim();
        const newStats = Array.from(document.querySelectorAll('.edit-stat-chk:checked')).map(cb => cb.value);
        if (!newTitle) return UI.showToast("Title cannot be empty", "danger");
        if (newStats.length === 0) return UI.showToast("Select at least one Stat", "danger");
        let item;
        if (type === 'TASK') item = Store.tasks.find(i => i.id == id);
        else if (type === 'HABIT') item = Store.habits.find(i => i.id == id);
        else if (type === 'RAID') item = Store.raids.find(i => i.id == id);
        if (item) {
            item.title = newTitle;
            item.desc = newDesc;
            item.stats = newStats;
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-edit-only');
            UI.showToast("Data Updated Successfully ✨", "success");
        }
    },

    Inject: () => {
        try {
            const mode = document.getElementById('inj-mode').value;
            const editId = document.getElementById('inj-edit-id').value;
            if (mode === 'IMPORT') {
                Engine.handleJSONImport();
                return;
            }
            const data = Engine.getInjectionData();
            if (!data.title) {
                return UI.showToast("Title Required ⚠️", "danger");
            }
            if (editId) {
                if (mode === 'TASK') Store.tasks = Store.tasks.filter(x => x.id != editId);
                if (mode === 'HABIT') Store.habits = Store.habits.filter(x => x.id != editId);
                if (mode === 'RAID') Store.raids = Store.raids.filter(x => x.id != editId);
            }
            switch (mode) {
                case 'TASK':  Engine.processTask(data, editId);  break;
                case 'HABIT': Engine.processHabit(data, editId); break;
                case 'RAID':  Engine.processRaid(data, editId);  break;
                default:      UI.showToast("Unknown protocol", "danger"); return;
            }
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-inject');
            UI.clearInjectionForm();
        } catch(e) {
            console.error('Injection Error:', e);
            UI.showToast("Error: " + e.message, "danger");
        }
    },

    getInjectionData: () => ({
        title: document.getElementById('inj-title').value.trim(),
        desc: document.getElementById('inj-desc').value.trim(),
        size: document.getElementById('inj-size').value,
        linkedSkill: document.getElementById('inj-skill').value,
        stats: Array.from(document.querySelectorAll('.inj-stat-chk:checked')).map(cb => cb.value),
        activeDays: Array.from(document.querySelectorAll('#field-days input:checked')).map(cb => parseInt(cb.value)),
        startDate: document.getElementById('inj-start-date') ? document.getElementById('inj-start-date').value : null,
        startW: document.getElementById('inj-start-w').value,
        endW: document.getElementById('inj-end-w').value,
    }),

    handleJSONImport: () => {
        const raw = document.getElementById('inj-import-data').value;
        if (!raw) return UI.showToast("No Code Provided ⚠️", "danger");
        try {
            const data = JSON.parse(raw);
            if (Array.isArray(data)) {
                let count = { raids: 0, items: 0, tasks: 0, habits: 0, skills: 0 };
                data.forEach(item => {
                    const newId = item.id || `${Date.now()}_${Math.random()}`;
                    item.id = newId;
                    if (item.type === 'RAID') { Store.raids.push(item); count.raids++; }
                    else if (item.type === 'SHOP') { if(!item.id.startsWith('c-')) item.id = 'c-' + newId; Store.shopCustom.push(item); count.items++; }
                    else if (item.type === 'TASK') { Store.tasks.push(item); count.tasks++; }
                    else if (item.type === 'HABIT') { Store.habits.push(item); count.habits++; }
                    else if (item.type === 'SKILL') { Store.skills.push(item); count.skills++; }
                });
                const total = Object.values(count).reduce((a, b) => a + b, 0);
                UI.showToast(`✅ Imported ${total} Protocols`, "success");
            } else if (data.user && data.stats) {
                if(confirm("⚠️ WARNING: This is a full backup. It will overwrite everything. Continue?")) {
                    Store = data;
                    DataMgr.save();
                    location.reload();
                    return;
                }
            } else {
                throw new Error("Invalid JSON structure");
            }
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-inject');
            UI.clearInjectionForm();
        } catch(e) {
            UI.showToast("JSON Error: " + e.message, "danger");
        }
    },

    processTask: (data, editId) => {
        const uniqueId = editId || `${Date.now()}_${Math.floor(Math.random() * 1000)}`;
        let startW = data.startW ? parseInt(data.startW) : null;
        let isCampaign = startW !== null;
        let explicitDate = null;
        let cleanDesc = data.desc;
        const dateMatch = data.desc.match(/@W(\d+)D(\d+)/i);
        if (dateMatch) {
            explicitDate = { w: parseInt(dateMatch[1]), d: parseInt(dateMatch[2]) };
            cleanDesc = data.desc.replace(dateMatch[0], '').trim();
            isCampaign = true; 
        } else if (isCampaign) {
            explicitDate = { w: startW, d: 1 }; 
        }
        Store.tasks.push({ id: uniqueId, title: data.title, desc: cleanDesc, status: 'ACTIVE', stats: data.stats, linkedSkill: data.linkedSkill, size: data.size, dueDate: data.startDate || null, isCampaign: isCampaign, assignedDate: explicitDate });
        UI.showToast("Task Deployed ✅", "success");
    },

    processHabit: (data, editId) => {
        const uniqueId = editId || `h_${Date.now()}`;
        const oldHabit = editId ? Store.habits.find(h => h.id == editId) : null;
        Store.habits.push({ id: uniqueId, title: data.title, desc: data.desc, stats: data.stats, linkedSkill: data.linkedSkill, size: data.size, streak: oldHabit ? oldHabit.streak : 0, broken: false, history: oldHabit ? oldHabit.history : {}, createdAt: oldHabit ? oldHabit.createdAt : uniqueId, activeDays: data.activeDays.length > 0 ? data.activeDays : [0, 1, 2, 3, 4, 5, 6] });
        UI.showToast("Habit Set 🔥", "success");
    },

    processRaid: (data, editId) => {
        const uniqueId = editId || `${Date.now()}_${Math.floor(Math.random() * 1000)}`;
        let startW = data.startW ? parseInt(data.startW) : null;
        let endW = data.endW ? parseInt(data.endW) : null;
        const lines = data.desc.split('\n');
        const steps = [];
        let finalDesc = "";
        lines.forEach(line => {
            if (!line.trim()) return;
            if (steps.length === 0 && !line.includes('@') && !line.startsWith('-')) {
                finalDesc += line + "\n";
                return;
            }
            const dateMatch = line.match(/@W(\d+)D(\d+)/i);
            let explicitDate = null;
            let cleanText = line.trim();
            if (dateMatch) {
                explicitDate = { w: parseInt(dateMatch[1]), d: parseInt(dateMatch[2]) };
                cleanText = line.replace(dateMatch[0], '').replace(/^-/, '').trim();
            }
            steps.push({ id: steps.length + 1, txt: cleanText, desc: '', status: 'PENDING', assignedDate: explicitDate });
        });
        if (steps.length === 0) return UI.showToast("Raid needs steps!", "danger");
        steps[0].status = 'ACTIVE';
        const isCampaign = (startW !== null && endW !== null);
        if (isCampaign) {
            const totalWeeks = endW - startW + 1;
            steps.forEach((step, index) => {
                if (step.assignedDate) return;
                const progress = index / (steps.length - 1 || 1); 
                const offsetWeek = Math.floor(progress * (totalWeeks - 1));
                step.assignedDate = { w: startW + offsetWeek, d: (index % 7) + 1 };
            });
        }
        Store.raids.push({ id: uniqueId, title: data.title, desc: finalDesc.trim() || "Tactical Raid", steps, status: 'ACTIVE', stats: data.stats, linkedSkill: data.linkedSkill, size: data.size, isCampaign: isCampaign });
        UI.showToast("Raid Deployed ⚔️", "danger");
    },

    clearInjectionForm: () => {
        document.getElementById('inj-edit-id').value = '';
        document.getElementById('inj-title').value = '';
        document.getElementById('inj-desc').value = '';
        document.getElementById('inj-skill').selectedIndex = 0;
        document.getElementById('inj-start-w').value = '';
        document.getElementById('inj-end-w').value = '';
        document.querySelectorAll('.inj-stat-chk').forEach(cb => cb.checked = false);
        document.querySelectorAll('#field-days input').forEach(cb => cb.checked = true);
        if(document.getElementById('inj-start-date')) document.getElementById('inj-start-date').value = '';
    },

    markHabit: (id, status) => {
        const h = Store.habits.find(i => i.id.toString() === id.toString());
        if (!h) {
            UI.showToast("Error: Habit not found", "danger");
            return;
        }
        const today = new Date().toDateString();
        if (h.history[today]) {
            UI.showToast("Already marked today", "neutral");
            return;
        }
        h.history[today] = status;
        if (status === 'DONE') {
            if(h.broken) h.broken = false; 
            h.streak++;
            const sizeData = CONFIG.HABIT_SIZES[h.size || 'NORMAL'];
            const xpGain = sizeData.xp; 
            const goldGain = sizeData.gold;
            Engine.reward(xpGain, goldGain);
            const statsToBuff = h.stats || [h.stat] || ['DIS'];
            statsToBuff.forEach(statKey => {
                const buffValue = h.size === 'BIG' ? 2 : h.size === 'SMALL' ? 0.5 : 1;
                Store.stats[statKey] = (Store.stats[statKey] || 0) + buffValue;
            });
            if(h.linkedSkill) Engine.trainSkill(h.linkedSkill, 10);
            Engine.log('HABIT', `✅ EXECUTED: ${h.title}`, 'SUCCESS');
            UI.showToast(`+${xpGain} XP, +${goldGain} Gold`, "success");
        } else {
            if(h.streak >= 21) {
                h.broken = true;
                UI.showToast("⚠️ Core Habit Broken!", "danger");
            } else {
                const old = h.streak;
                h.streak = (old>=14) ? 14 : (old>=7) ? 7 : 0;
            }
            Engine.log('HABIT', `❌ MISSED: ${h.title}`, 'FAILURE');
        }
        DataMgr.save();
        Engine.checkAchievements();
        UI.renderAll();
    },

    completeTask: (id) => {
        const t = Store.tasks.find(x => x.id == id);
        if(!t) {
            UI.showToast("Error: Task not found", "danger");
            return;
        }
        t.status = 'DONE';
        const sizeData = CONFIG.HABIT_SIZES[t.size || 'NORMAL'];
        const xpGain = sizeData.xp;
        const goldGain = sizeData.gold;
        Engine.reward(xpGain, goldGain);
        const statsToBuff = t.stats || ['DIS'];
        statsToBuff.forEach(statKey => {
            const val = (t.size === 'BIG' ? 1.5 : t.size === 'SMALL' ? 0.25 : 0.5);
            Store.stats[statKey] = (Store.stats[statKey] || 0) + val;
        });
        if(t.linkedSkill) Engine.trainSkill(t.linkedSkill, 20);
        Engine.log('TASK', `✅ DONE: ${t.title}`, 'SUCCESS');
        UI.showToast(`Task Complete! +${xpGain} XP`, "success");
        DataMgr.save();
        Engine.checkAchievements();
        UI.renderAll();
    },

    advanceRaid: (raidId) => {
        const r = Store.raids.find(x => x.id.toString() === raidId.toString());
        if(!r) {
            UI.showToast("Error: Raid not found", "danger");
            return;
        }
        const sizeKey = r.size || 'NORMAL'; 
        const diffData = CONFIG.HABIT_SIZES[sizeKey];
        const step = r.steps.find(s => s.status === 'ACTIVE');
        if(step) {
            step.status = 'DONE';
            const stepXp = diffData.xp;
            const stepGold = diffData.gold * 0.5;
            Engine.reward(stepXp, stepGold);
            if(r.linkedSkill) Engine.trainSkill(r.linkedSkill, 15);
            if(r.stats) {
                r.stats.forEach(s => {
                    Store.stats[s] = (Store.stats[s] || 0) + 0.2;
                });
            }
            UI.showToast("Target Hit! Enemy Damaged.", "success");
            const next = r.steps.find(s => s.id === step.id + 1);
            if(next) {
                next.status = 'ACTIVE';
            } else {
                r.status = 'COMPLETED';
                const bigXp = diffData.xp * 5;
                const bigGold = diffData.gold * 10;
                Engine.reward(bigXp, bigGold);
                Store.achievements.push({ id: Date.now(), title: `Raid Clear: ${r.title}`, desc: `Completed ${sizeKey}`, icon: "🏆" });
                Engine.log('RAID', `🏆 CLEARED: ${r.title}`, 'SUCCESS');
                UI.showToast(`RAID CLEARED! +${bigGold} Gold`, "gold");
            }
            DataMgr.save();
            Engine.checkAchievements();
            UI.renderAll();
        }
    },

    deleteRaid: (id) => {
        if(confirm("⚠️ ABORT MISSION? \nAre you sure you want to delete this Raid permanently?")) {
            Store.raids = Store.raids.filter(r => r.id != id);
            DataMgr.save();
            UI.renderAll();
            UI.showToast("Raid Protocol Aborted.", "danger");
        }
    },

    checkAchievements: () => {
        let newUnlock = false;
        CONFIG.TROPHY_DB.forEach(rule => {
            if (Store.achievements.some(a => a.id === rule.id)) return;
            let passed = false;
            if (rule.type === 'GOLD' && Store.user.gold >= rule.val) passed = true;
            else if (rule.type === 'STREAK' && Store.user.streak >= rule.val) passed = true;
            else if (rule.type === 'LEVEL' && Store.user.lvl >= rule.val) passed = true;
            else if (CONFIG.STATS[rule.type] && Store.stats[rule.type] >= rule.val) passed = true;
            if (passed) {
                Store.achievements.push({ id: rule.id, title: rule.title, desc: rule.desc, date: new Date().toLocaleDateString(), icon: rule.icon });
                Engine.log('SYSTEM', `TROPHY UNLOCKED: ${rule.title}`, 'SUCCESS');
                newUnlock = true;
            }
        });
        if(newUnlock) DataMgr.save();
    },

    buyItem: (id, cost, title) => {
        if(Store.user.gold >= cost) {
            Store.user.gold -= cost;
            Engine.log('SHOP', `BOUGHT: ${title}`, 'NEUTRAL');
            DataMgr.save();
            UI.renderAll();
        } else alert("INSUFFICIENT GOLD");
    },

    reward: (xp, gold) => {
        Store.user.xp += xp; 
        Store.user.gold += gold;
        if(!Store.user.dailyXp) Store.user.dailyXp = 0;
        Store.user.dailyXp += xp;
        const targets = { 'EASY': 300, 'NORMAL': 400, 'HARD': 500 };
        const mode = Store.user.streakMode || 'NORMAL';
        const target = targets[mode];
        if (!Store.user.streakDoneToday) Store.user.streakDoneToday = false;
        if (Store.user.dailyXp >= target && !Store.user.streakDoneToday) {
            Store.user.streak++;
            Store.user.streakDoneToday = true;
            UI.showToast("🔥 STREAK SAVED! DAY COMPLETE", "danger");
            Engine.log('SYSTEM', 'DAILY TARGET DESTROYED', 'SUCCESS');
        }
        if(Store.user.xp >= CONFIG.LEVEL_THRESHOLD) {
            Store.user.lvl++; Store.user.xp -= CONFIG.LEVEL_THRESHOLD;
            UI.showToast(`LEVEL UP! You are now Lvl ${Store.user.lvl}`, "gold");
        }
        DataMgr.save(); 
    },

    log: (type, msg, tone) => {
        Store.globalHistory.unshift({ time: new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}), type, msg, tone });
        if(Store.globalHistory.length > 50) Store.globalHistory.pop();
    },

    toggleArchive: (id, type) => {
        let item;
        if (type === 'HABIT') item = Store.habits.find(i => i.id == id);
        else if (type === 'TASK') item = Store.tasks.find(i => i.id == id);
        else if (type === 'RAID') item = Store.raids.find(i => i.id == id);
        if (item) {
            item.archived = !item.archived;
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-details');
            UI.showToast(item.archived ? "Archived 📂" : "Restored ♻️", "neutral");
        }
    },

    deleteTask: (id) => {
        if(confirm("⚠️ Delete Task Permanently?")) {
            Store.tasks = Store.tasks.filter(t => t.id != id);
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-details');
            UI.showToast("Task Deleted", "danger");
        }
    },

    deleteHabit: (id) => {
        const h = Store.habits.find(i => i.id.toString() === id.toString());
        if(!h) return;
        Swal.fire({
            title: '⚠️ SYSTEM WARNING',
            html: `Are you sure you want to <b>TERMINATE</b> the protocol:<br><br><span style="color:#ff4b4b; font-size:1.2rem; font-weight:bold;">[ ${escapeHTML(h.title)} ]</span>?<br><br>This action is irreversible.`,
            icon: 'warning',
            background: '#150505',
            color: '#fff',
            showCancelButton: true,
            confirmButtonText: '🗑️ DELETE',
            cancelButtonText: 'CANCEL',
            confirmButtonColor: '#ff4b4b',
            cancelButtonColor: '#333',
            backdrop: `rgba(255,0,0,0.1)`,
            willOpen: () => {
                const popup = Swal.getPopup();
                popup.style.border = '2px solid #ff4b4b';
                popup.style.boxShadow = '0 0 20px rgba(255, 75, 75, 0.4)';
                popup.style.borderRadius = '12px';
            }
        }).then((result) => {
            if (result.isConfirmed) {
                Store.habits = Store.habits.filter(i => i.id.toString() !== id.toString());
                DataMgr.save();
                UI.renderAll();
                UI.closeModal('modal-details');
                Swal.fire({ title: 'TERMINATED', text: 'Protocol purged from memory.', icon: 'success', background: '#000', confirmButtonColor: '#58cc02', timer: 1500, showConfirmButton: false });
            }
        });
    },

    setCampaignStart: (dateString) => {
        if (!dateString) return;
        if (!Store.season) Store.season = {};
        Store.season.startDate = dateString;
        DataMgr.save();
        UI.renderWar();
        UI.showToast(`ZERO HOUR UPDATED: ${dateString}`, 'success');
    },

    createHabitSection: () => {
        Swal.fire({ title: 'NEW FOLDER', input: 'text', inputPlaceholder: 'e.g., Gym Arc, Studies...', background: '#000', color: '#fff', confirmButtonColor: '#58cc02', showCancelButton: true })
        .then((res) => {
            if (res.isConfirmed && res.value) {
                const name = res.value.trim();
                if (!Store.habitSections.includes(name)) {
                    Store.habitSections.push(name);
                    DataMgr.save();
                    UI.renderAll();
                    UI.showToast(`Folder "${name}" Created`, "success");
                }
            }
        });
    },

    deleteSection: (secName) => {
        if(confirm(`Delete folder "${secName}"? Habits inside will move to General.`)) {
            Store.habits.forEach(h => { if (h.section === secName) h.section = 'General'; });
            Store.habitSections = Store.habitSections.filter(s => s !== secName);
            DataMgr.save();
            UI.renderAll();
            UI.showToast("Folder Deleted", "neutral");
        }
    },

    moveHabit: (id) => {
        const buttons = Store.habitSections.map(sec => `<button onclick="Engine.setHabitSection('${id}', '${sec}')" style="width:100%; padding:12px; margin-bottom:5px; background:#111; border:1px solid #444; color:#fff; border-radius:8px; cursor:pointer; font-weight:bold;">📂 ${escapeHTML(sec)}</button>`).join('');
        Swal.fire({ title: 'MOVE TO...', html: `<div style="max-height:300px; overflow-y:auto;">${buttons}</div>`, background: '#000', showConfirmButton: false, showCloseButton: true });
    },

    setHabitSection: (id, secName) => {
        const h = Store.habits.find(i => i.id == id);
        if (h) {
            h.section = secName;
            DataMgr.save();
            UI.renderAll();
            Swal.close();
            UI.showToast(`Moved to ${secName}`, "success");
        }
    },

    createShopSection: () => {
        Swal.fire({ title: 'NEW AISLE', input: 'text', inputPlaceholder: 'e.g., Food, Tech, Gaming...', background: '#000', color: '#fff', confirmButtonColor: '#ffc800', showCancelButton: true })
        .then((res) => {
            if (res.isConfirmed && res.value) {
                const name = res.value.trim();
                if (!Store.shopSections.includes(name)) {
                    Store.shopSections.push(name);
                    DataMgr.save();
                    UI.renderShop();
                    UI.showToast(`Aisle "${name}" Opened`, "gold");
                }
            }
        });
    },

    deleteShopSection: (secName) => {
        if(confirm(`Close "${secName}" aisle? Items will move to General.`)) {
            Store.shopCustom.forEach(i => { if (i.section === secName) i.section = 'General'; });
            Store.shopSections = Store.shopSections.filter(s => s !== secName);
            DataMgr.save();
            UI.renderShop();
            UI.showToast("Aisle Closed", "neutral");
        }
    },

    moveShopItem: (id) => {
        const buttons = Store.shopSections.map(sec => `<button onclick="Engine.setShopSection('${id}', '${sec}')" style="width:100%; padding:12px; margin-bottom:5px; background:#111; border:1px solid #444; color:var(--warning); border-radius:8px; cursor:pointer; font-weight:bold;">🛍️ ${escapeHTML(sec)}</button>`).join('');
        Swal.fire({ title: 'MOVE STOCK TO...', html: `<div style="max-height:300px; overflow-y:auto;">${buttons}</div>`, background: '#000', showConfirmButton: false, showCloseButton: true });
    },

    setShopSection: (id, secName) => {
        const item = Store.shopCustom.find(i => i.id == id);
        if (item) {
            item.section = secName;
            DataMgr.save();
            UI.renderShop();
            Swal.close();
            UI.showToast(`Moved to ${secName}`, "gold");
        }
    }
};

// --- 5. DATA MANAGER ---
const DataMgr = {
    save: () => {
        try {
            localStorage.setItem('LifeOS_V7_Final', JSON.stringify(Store));
        } catch(e) {
            console.error('Save Error:', e);
            UI.showToast("Save Error", "danger");
        }
    },
    load: () => { 
        const d = localStorage.getItem('LifeOS_V7_Final');
        if(d) {
            try {
                const parsed = JSON.parse(d);
                Store.user = parsed.user || Store.user;
                Store.season = parsed.season || { startDate: new Date().toISOString().split('T')[0], active: true };
                Store.stats = (!parsed.stats || Object.keys(parsed.stats).length === 0) ? { STR: 0, DIS: 0, INT: 0, CHR: 0, EMT: 0, PCE: 0 } : parsed.stats;
                Store.skills = Array.isArray(parsed.skills) ? parsed.skills : [];
                Store.tasks = parsed.tasks || [];
                Store.raids = parsed.raids || [];
                Store.achievements = parsed.achievements || [];
                Store.shopCustom = parsed.shopCustom || [];
                Store.globalHistory = parsed.globalHistory || [];
                Store.habits = Array.isArray(parsed.habits) ? parsed.habits : Object.entries(parsed.habits || {}).map(([key, val]) => { val.id = key; return val; });
                if (!Store.habitSections || Store.habitSections.length === 0) Store.habitSections = ['General']; 
                Store.habits.forEach(h => { if (!h.section) h.section = 'General'; });
                if (!Store.shopSections || Store.shopSections.length === 0) Store.shopSections = ['General']; 
                if (Store.shopCustom) Store.shopCustom.forEach(item => { if (!item.section) item.section = 'General'; });
                if(!Store.user.lastLogin) Store.user.lastLogin = new Date().toDateString();
                DataMgr.save();
            } catch(e) { 
                UI.showToast("Data Recovered with defaults", "warning");
            }
        }
    },
    exportData: () => {
        try {
            const blob = new Blob([JSON.stringify(Store, null, 2)], {type: "application/json"});
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; 
            a.download = `LifeOS_Backup_${new Date().toISOString().slice(0,10)}.json`;
            a.click();
            UI.showToast("Backup created", "success");
        } catch(e) {
            UI.showToast("Export failed", "danger");
        }
    },
    importData: (input) => {
        const file = input.files[0];
        if(!file) return;
        const reader = new FileReader();
        reader.onload = (e) => {
            try { 
                const imported = JSON.parse(e.target.result);
                if(imported.user) {
                    Object.assign(Store, imported);
                    DataMgr.save();
                    UI.showToast("Data restored successfully", "success");
                    setTimeout(() => location.reload(), 1000);
                } else { throw new Error("Invalid structure"); }
            } 
            catch(err) { alert("⚠️ Corrupted File"); }
        };
        reader.readAsText(file);
    }
};

