// --- 3. THE ENGINE (LOGIC) ---
const Engine = {
    init: () => {
        DataMgr.load();
        const today = new Date().toDateString();
        if (Store.user.lastLogin !== today) {
            Engine.dailyReset();
            Store.user.lastLogin = today;
            DataMgr.save();
        }
        if(!Store.skills) Store.skills = [];
        Engine.checkAchievements();
        UI.renderAll();
    },

    archiveStepAsTask: () => {
        const rId = document.getElementById('step-raid-id').value;
        const sId = document.getElementById('step-id').value;
        if(!rId || !sId) return;
        const r = Store.raids.find(x => x.id == rId);
        if(!r) return;

        const step = r.steps.find(s => s.id == sId);
        if(step) {
            const newTask = {
                id: `arch_step_${Date.now()}`,
                title: `[RAID LOG] ${step.txt}`, 
                desc: `Source: ${r.title}\n\n${step.desc || ''}`,
                status: 'ACTIVE',
                stats: r.stats || ['STR'],
                linkedSkill: r.linkedSkill,
                size: r.size,
                archived: true,
                origin: { raidId: rId, stepId: sId }
            };
            Store.tasks.push(newTask);
            step.delegated = true; 
            DataMgr.save();
            UI.renderAll();
            UI.closeModal('modal-step-control');
            UI.showToast("Step moved to Archive 📂", "gold");
        }
    },

    restoreStep: (taskId) => {
        const taskIndex = Store.tasks.findIndex(t => t.id == taskId);
        if (taskIndex === -1) return;
        const task = Store.tasks[taskIndex];
        if (task.origin && task.origin.raidId) {
            const r = Store.raids.find(x => x.id == task.origin.raidId);
            if (r) {
                const step = r.steps.find(s => s.id == task.origin.stepId);
                if (step) {
                    step.delegated = false;
                    Store.tasks.splice(taskIndex, 1);
                    DataMgr.save();
                    UI.renderAll();
                    UI.closeModal('modal-details'); 
                    UI.showToast("Step Restored to Raid 🔄", "success");
                    return;
                }
            }
        }
        UI.showToast("Error: Original Raid not found", "danger");
    },

    saveStepUpdate: () => {
        const rId = document.getElementById('step-raid-id').value;
        const sId = parseInt(document.getElementById('step-id').value);
        const txt = document.getElementById('step-txt').value.trim();
        const desc = document.getElementById('step-desc').value.trim();
        const r = Store.raids.find(x => x.id == rId);
        if(r) {
            const step = r.steps.find(s => s.id === sId);
            if(step) {
                step.txt = txt;
                step.desc = desc;
                DataMgr.save();
                UI.renderAll();
                UI.closeModal('modal-step-control');
                UI.showToast("Tactical Update Confirmed", "success");
            }
        }
    },

    dailyReset: () => {
        Engine.log('SYSTEM', 'NEW DAY PROTOCOL INITIALIZED', 'NEUTRAL');
        if (!Store.user.streakDoneToday && !Store.user.streakShield) {
            if(Store.user.streak > 0) {
                UI.showToast("💀 STREAK LOST! You failed the mission.", "danger");
                Engine.log('SYSTEM', `STREAK RESET (Was: ${Store.user.streak})`, 'FAILURE');
            }
            Store.user.streak = 0;
        } else if (Store.user.streakShield && !Store.user.streakDoneToday) {
            UI.showToast("🛡️ SHIELD ACTIVATED! Streak Saved.", "gold");
            Store.user.streakShield = false;
            Engine.log('SYSTEM', 'STREAK FROZEN BY SHIELD', 'NEUTRAL');
        }
        Store.user.dailyXp = 0;
        Store.user.streakDoneToday = false; 
        DataMgr.save();
    },

    getWarStatus: () => {
        const startStr = Store.season.startDate || new Date().toISOString();
        const start = new Date(startStr);
        const now = new Date();
        // Reset time part for accurate day calculation
        start.setHours(0,0,0,0);
        now.setHours(0,0,0,0);

        const diffTime = now - start; 
        const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24)); 

        // Calculate week (0-indexed then +1)
        let currentWeek = Math.floor(diffDays / 7) + 1;

        // Handle pre-season
        if (diffDays < 0) currentWeek = 0;

        return { currentWeek, diffDays };
    },

