        if(confirm(`Forget skill "${skillTitle}"? Progress will be lost.`)) {
            Store.skills = Store.skills.filter(s => (typeof s === 'string' ? s : s.title) !== skillTitle);
            DataMgr.save();
            UI.renderProfile();
        }
