        if(confirm(`Delete folder "${secName}"? Habits inside will move to General.`)) {
            Store.habits.forEach(h => { if (h.section === secName) h.section = 'General'; });
            Store.habitSections = Store.habitSections.filter(s => s !== secName);
            DataMgr.save();
            UI.renderAll();
            UI.showToast("Folder Deleted", "neutral");
        }
    },

    moveHabit: (id) => {
        const buttons = Store.habitSections.map(sec => `<button onclick="Engine.setHabitSection('${id}', '${sec}')" style="width:100%; padding:12px; margin-bottom:5px; background:#111; border:1px solid #444; color:#fff; border-radius:8px; cursor:pointer; font-weight:bold;">📂 ${escapeHTML(sec)}</button>`).join('');
        Swal.fire({ title: 'MOVE TO...', html: `<div style="max-height:300px; overflow-y:auto;">${buttons}</div>`, background: '#000', showConfirmButton: false, showCloseButton: true });
    },

    setHabitSection: (id, secName) => {
        const h = Store.habits.find(i => i.id == id);
        if (h) {
            h.section = secName;
            DataMgr.save();
            UI.renderAll();
            Swal.close();
            UI.showToast(`Moved to ${secName}`, "success");
        }
    },

    createShopSection: () => {
        Swal.fire({ title: 'NEW AISLE', input: 'text', inputPlaceholder: 'e.g., Food, Tech, Gaming...', background: '#000', color: '#fff', confirmButtonColor: '#ffc800', showCancelButton: true })
        .then((res) => {
            if (res.isConfirmed && res.value) {
                const name = res.value.trim();
                if (!Store.shopSections.includes(name)) {
                    Store.shopSections.push(name);
                    DataMgr.save();
                    UI.renderShop();
                    UI.showToast(`Aisle "${name}" Opened`, "gold");
                }
            }
        });
    },

    deleteShopSection: (secName) => {
        if(confirm(`Close "${secName}" aisle? Items will move to General.`)) {
            Store.shopCustom.forEach(i => { if (i.section === secName) i.section = 'General'; });
            Store.shopSections = Store.shopSections.filter(s => s !== secName);
            DataMgr.save();
            UI.renderShop();
            UI.showToast("Aisle Closed", "neutral");
        }
    },

    moveShopItem: (id) => {
        const buttons = Store.shopSections.map(sec => `<button onclick="Engine.setShopSection('${id}', '${sec}')" style="width:100%; padding:12px; margin-bottom:5px; background:#111; border:1px solid #444; color:var(--warning); border-radius:8px; cursor:pointer; font-weight:bold;">🛍️ ${escapeHTML(sec)}</button>`).join('');
        Swal.fire({ title: 'MOVE STOCK TO...', html: `<div style="max-height:300px; overflow-y:auto;">${buttons}</div>`, background: '#000', showConfirmButton: false, showCloseButton: true });
    },

    setShopSection: (id, secName) => {
        const item = Store.shopCustom.find(i => i.id == id);
        if (item) {
            item.section = secName;
            DataMgr.save();
            UI.renderShop();
            Swal.close();
            UI.showToast(`Moved to ${secName}`, "gold");
        }
    }
};

// --- 5. UI RENDERER ---
const UI_ICONS = { STR: '💪', DIS: '🛡️', INT: '🧠', CHR: '🎭', EMT: '❤️', PCE: '🧘', SKILL: '⚡' };
const UI = {
    opsMode: 'NORMAL',
    tempTrophy: null,
    tempTierIdx: 0,
    currentWeekEdit: null,
    currentWarView: { w: 1, d: 1 },
    hubMode: 'NORMAL',
    calDate: new Date(),

    toggleOps: (btn) => {
        const isActive = btn.classList.contains('active');
        if (!isActive) {
            UI.nav(UI.opsMode === 'WAR' ? 'view-ops-war' : 'view-ops', btn);
        } else {
            UI.opsMode = (UI.opsMode === 'NORMAL') ? 'WAR' : 'NORMAL';
            UI.nav(UI.opsMode === 'WAR' ? 'view-ops-war' : 'view-ops', btn);
            if (UI.opsMode === 'WAR') UI.renderWar();
            UI.showToast(UI.opsMode === 'WAR' ? "⚠️ WAR MODE ENGAGED" : "Standard Ops Resumed", UI.opsMode === 'WAR' ? "danger" : "neutral");
        }
    },

    toggleHub: (btn) => {
        const isActive = btn.classList.contains('active');
        if (!isActive) {
            UI.nav('view-hub', btn);
            UI.hubMode = 'NORMAL';
        } else {
            UI.hubMode = (UI.hubMode === 'NORMAL') ? 'CALENDAR' : 'NORMAL';
            UI.nav(UI.hubMode === 'CALENDAR' ? 'view-hub-calendar' : 'view-hub', btn);
            if (UI.hubMode === 'CALENDAR') {
                UI.renderCalendar();
                UI.showToast("📅 MONTHLY OVERVIEW", "gold");
            }
        }
    },

    nav: (pageId, btn) => {
        document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
        document.getElementById(pageId)?.classList.add('active');
        document.querySelectorAll('.nav-item').forEach(n => {
            n.classList.remove('active');
            n.style.color = '';
            n.style.textShadow = '';
        });
        if (btn) {
            btn.classList.add('active');
            if (pageId === 'view-ops-war') {
                btn.style.color = 'var(--danger)';
                btn.style.textShadow = '0 0 15px var(--danger)';
            }
        }
    },

    closeModal: (id) => {
        document.getElementById(id)?.classList.remove('active');
    },

    openNew: (type) => {
        document.getElementById('modal-inject')?.classList.add('active');
        document.getElementById('inj-mode').value = type;
        document.getElementById('inj-edit-id').value = '';
        UI.updateSkillsDropdown();
        UI.switchInjectMode(type);
    },

    updateSkillsDropdown: () => {
        const dropdown = document.getElementById('inj-skill');
        if(!dropdown) return;
        dropdown.innerHTML = '<option value="">-- No Specific Skill --</option>';
        Store.skills.forEach(s => {
            const title = (typeof s === 'object') ? s.title : s;
            const icon = (typeof s === 'object') ? (s.icon || '⚡') : '⚡';
            dropdown.innerHTML += `<option value="${escapeHTML(title)}">${icon} ${escapeHTML(title)}</option>`;
        });
    },

    switchInjectMode: (mode) => {
        document.getElementById('inj-mode').value = mode;
        document.querySelectorAll('#field-type-select .btn-3d').forEach(b => b.classList.remove('active-mode'));
        document.getElementById(`btn-mode-${mode}`)?.classList.add('active-mode');
        ['group-common', 'group-gamified', 'group-shop', 'group-patch', 'group-batch', 'group-import'].forEach(g => document.getElementById(g)?.classList.add('hidden'));
        if(document.getElementById('field-days')) document.getElementById('field-days').classList.add('hidden');
        if(document.getElementById('field-date-range')) document.getElementById('field-date-range').classList.add('hidden');

        // Handle War Room range inputs visibility
        const rangeInputs = document.getElementById('war-range-inputs');
        if(rangeInputs) rangeInputs.classList.add('hidden');

        if (['TASK', 'HABIT', 'RAID'].includes(mode)) {
            document.getElementById('group-common')?.classList.remove('hidden');
            document.getElementById('group-gamified')?.classList.remove('hidden');
            document.getElementById('modal-title').innerText = `NEW ${mode}`;
            if (mode === 'HABIT') document.getElementById('field-days')?.classList.remove('hidden');
            else document.getElementById('field-date-range')?.classList.remove('hidden');

            // Show start/end week inputs for Task/Raid
            if ((mode === 'TASK' || mode === 'RAID') && rangeInputs) {
                rangeInputs.classList.remove('hidden');
            }
        } else if (mode === 'IMPORT') {
            document.getElementById('group-import')?.classList.remove('hidden');
            document.getElementById('modal-title').innerText = "SYSTEM RESTORE";
        }
    },

    selectSize: (size) => {
        document.getElementById('inj-size').value = size;
        ['SMALL', 'NORMAL', 'BIG'].forEach(s => {
            const btn = document.getElementById(`btn-size-${s}`);
            if(btn) {
                if(s === size) btn.classList.add('active-size');
                else btn.classList.remove('active-size');
            }
        });
    },

    renderAll: () => {
        document.getElementById('sb-lvl').innerText = Store.user.lvl;
        document.getElementById('sb-gold').innerText = Store.user.gold;
        document.getElementById('sb-streak').innerText = Store.user.streak;
        UI.renderProfile();
        UI.renderHabits();
        UI.renderTasks();
        UI.renderRaids();
        UI.renderShop();
        UI.renderHistory();
        if(UI.opsMode === 'WAR') UI.renderWar();
        if(UI.hubMode === 'CALENDAR') UI.renderCalendar();
    },

    renderProfile: () => {
        UI.renderStats();
        UI.renderSkills();
        UI.renderTrophies();
    },

    renderStats: () => {
        const zone = document.getElementById('zone-stats');
        if(!zone) return;
        zone.innerHTML = '';
        Object.entries(Store.stats).forEach(([key, val]) => {
            const pct = Math.min((val / 100) * 100, 100); 
            const icon = UI_ICONS[key] || '❓';
            zone.innerHTML += `
            <div style="margin-bottom:8px;">
                <div style="display:flex; justify-content:space-between; font-size:0.75rem; font-weight:800; color:var(--text-muted); margin-bottom:4px;">
                    <span>${icon} ${key}</span>
                    <span>${Math.floor(val)}</span>
                </div>
                <div class="progress-container"><div class="progress-fill" style="width:${pct}%; background:var(--stat-${key.toLowerCase()});"></div></div>
            </div>`;
        });
    },

    renderSkills: () => {
        const zone = document.getElementById('zone-skills-list');
        if(!zone) return;
        zone.innerHTML = '';
        if(Store.skills.length === 0) zone.innerHTML = `<div style="text-align:center; padding:20px; color:#555; font-size:0.8rem;">No Skills Yet</div>`;
        Store.skills.forEach(s => {
            const sTitle = (typeof s === 'object') ? s.title : s;
            const sLvl = (typeof s === 'object') ? s.lvl : 1;
            const sXp = (typeof s === 'object') ? s.xp : 0;
            const sMax = (typeof s === 'object') ? s.maxXp : 100;
            const icon = (typeof s === 'object') ? (s.icon || '⚡') : '⚡';
            const pct = Math.min((sXp / sMax) * 100, 100);
            zone.innerHTML += `
            <div style="background:rgba(255,255,255,0.03); border-radius:12px; padding:10px; margin-bottom:10px; position:relative;">
                <div style="position:absolute; top:10px; right:10px; cursor:pointer;" onclick="Engine.removeSkill('${escapeHTML(sTitle)}')">🗑️</div>
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:5px;">
                    <div style="font-weight:800; font-size:0.9rem; color:var(--inject);">${icon} ${escapeHTML(sTitle)}</div>
                    <div style="font-size:0.75rem; color:#fff; font-weight:bold;">Lv.${sLvl}</div>
                </div>
                <div class="progress-container" style="height:6px; background:#111;">
                    <div class="progress-fill" style="width:${pct}%; background:var(--inject);"></div>
                </div>
                <div style="text-align:right; font-size:0.65rem; color:#666; margin-top:3px;">${sXp} / ${sMax} XP</div>
            </div>`;
        });
    },

    renderTrophies: () => {
        const zone = document.getElementById('zone-trophies');
        if(!zone) return;
        zone.innerHTML = '';
        CONFIG.TROPHY_DB.forEach(t => {
            const earned = Store.achievements.find(a => a.id === t.id);
            const statusClass = earned ? 'unlocked' : 'locked';
            zone.innerHTML += `<div class="trophy-item ${statusClass}" onclick="UI.openTrophy('${t.id}')">
                <div style="font-size:1.5rem;">${t.icon}</div>
                <div style="font-size:0.6rem; font-weight:800; margin-top:5px; color:${earned ? 'var(--warning)' : '#555'};">${t.title}</div>
            </div>`;
        });
    },

    renderHabits: () => {
        const zone = document.getElementById('zone-habits-active');
        if(!zone) return;
        zone.innerHTML = '';

        const dayIndex = new Date().getDay();
        const today = new Date().toDateString();

        if(!Store.habitSections) Store.habitSections = ['General'];
        const organized = {};
        Store.habitSections.forEach(s => organized[s] = []);
        let uncategorized = [];

        Store.habits.forEach(h => {
            if (h.archived) return;
            const activeDays = h.activeDays || [0,1,2,3,4,5,6];
            if (!activeDays.includes(dayIndex)) return;
            if (h.section && organized[h.section]) organized[h.section].push(h);
            else {
                if(!h.section) h.section = 'General';
                if(organized['General']) organized['General'].push(h);
                else uncategorized.push(h);
            }
        });

        // Render sections
        const renderSection = (title, habits) => {
            if(habits.length === 0) return '';
            let html = `<div style="margin-bottom:20px;">
                <div style="display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid #333; padding-bottom:5px; margin-bottom:10px;">
                    <div style="font-size:0.75rem; font-weight:900; color:var(--text-muted); text-transform:uppercase; letter-spacing:1px;">${escapeHTML(title)}</div>
                    ${title !== 'General' ? `<div style="cursor:pointer; color:#555;" onclick="Engine.deleteSection('${escapeHTML(title)}')">✖</div>` : ''}
                </div>`;

            habits.forEach(h => {
                const done = h.history[today] === 'DONE';
                const missed = h.history[today] === 'MISSED';
                const bg = done ? 'rgba(88, 204, 2, 0.1)' : missed ? 'rgba(255, 75, 75, 0.1)' : 'var(--bg-panel)';
                const border = done ? 'var(--accent)' : missed ? 'var(--danger)' : 'var(--border)';

                // Determine phase color
                let phaseColor = CONFIG.HABIT_PHASES.NEW.color;
                if(h.streak >= 21) phaseColor = CONFIG.HABIT_PHASES.CORE.color;
                else if(h.streak >= 14) phaseColor = CONFIG.HABIT_PHASES.EVOLVED.color;
                else if(h.streak >= 7) phaseColor = CONFIG.HABIT_PHASES.STABLE.color;

                html += `
                <div class="habit-card" style="background:${bg}; border-color:${border}; display:flex; justify-content:space-between; align-items:center; padding:12px; border-radius:12px; margin-bottom:8px; border-width:2px; border-style:solid;">
                    <div onclick="UI.openDetails('${h.id}', 'HABIT')" style="flex:1; cursor:pointer;">
                        <div style="font-weight:800; font-size:0.95rem; color:#fff; display:flex; align-items:center; gap:6px;">
                            ${escapeHTML(h.title)}
                            ${h.broken ? '<i class="fas fa-heart-crack" style="color:var(--danger); font-size:0.7rem;"></i>' : ''}
                        </div>
                        <div style="font-size:0.7rem; color:var(--text-muted); margin-top:2px;">
                            <span style="color:${phaseColor}; font-weight:bold;">🔥 ${h.streak}</span> • ${h.size || 'NORMAL'}
                        </div>
                    </div>

                    <div style="display:flex; gap:8px;">
                         ${!done && !missed ? `
                            <button class="btn-3d danger" style="padding:6px 12px; font-size:0.8rem;" onclick="Engine.markHabit('${h.id}', 'MISSED')">✖</button>
                            <button class="btn-3d success" style="padding:6px 12px; font-size:0.8rem;" onclick="Engine.markHabit('${h.id}', 'DONE')">✔</button>
                         ` : `
                            <div style="font-weight:900; color:${done ? 'var(--accent)' : 'var(--danger)'}; font-size:1.2rem; padding-right:10px;">
                                ${done ? 'COMPLETE' : 'FAILED'}
                            </div>
                         `}
                    </div>
                </div>`;
            });
            html += `</div>`;
            return html;
        };

        Store.habitSections.forEach(sec => {
            zone.innerHTML += renderSection(sec, organized[sec]);
        });

        zone.innerHTML += `<div style="text-align:center; margin-top:15px;">
            <button onclick="Engine.createHabitSection()" style="background:transparent; border:1px dashed #555; color:#777; padding:8px 15px; border-radius:20px; font-size:0.7rem; cursor:pointer;">+ NEW FOLDER</button>
        </div>`;
    },

    renderTasks: () => {
        const zone = document.getElementById('zone-tasks');
        if(!zone) return;
        zone.innerHTML = '';

        const active = Store.tasks.filter(t => t.status === 'ACTIVE' && !t.archived && !t.isCampaign);
        const campaign = Store.tasks.filter(t => t.status === 'ACTIVE' && !t.archived && t.isCampaign);

        if(active.length === 0 && campaign.length === 0 && Store.raids.filter(r=>r.status === 'ACTIVE').length === 0) {
            document.getElementById('ops-empty').classList.remove('hidden');
        } else {
            document.getElementById('ops-empty').classList.add('hidden');
        }

        const renderItem = (t) => `
        <div class="game-row" style="border-left:4px solid var(--stat-int);">
            <div style="flex:1; cursor:pointer;" onclick="UI.openDetails('${t.id}', 'TASK')">
                <div style="font-weight:800; font-size:0.9rem;">${escapeHTML(t.title)}</div>
                <div style="display:flex; gap:5px; margin-top:5px;">
                    <span class="meta-tag tag-normal">${t.size || 'NORMAL'}</span>
                    ${t.linkedSkill ? `<span class="meta-tag tag-skill">${escapeHTML(t.linkedSkill)}</span>` : ''}
                </div>
            </div>
            <button class="btn-3d success" style="padding:8px 14px;" onclick="Engine.completeTask('${t.id}')">
                <i class="fas fa-check"></i>
            </button>
        </div>`;

        if(campaign.length > 0) {
            zone.innerHTML += `<div style="font-size:0.7rem; font-weight:900; color:var(--text-muted); margin-bottom:10px;">CAMPAIGN OBJECTIVES</div>`;
            campaign.forEach(t => zone.innerHTML += renderItem(t));
        }

        if(active.length > 0) {
             zone.innerHTML += `<div style="font-size:0.7rem; font-weight:900; color:var(--text-muted); margin:15px 0 10px 0;">SIDE MISSIONS</div>`;
             active.forEach(t => zone.innerHTML += renderItem(t));
        }
    },

    renderRaids: () => {
        const zone = document.getElementById('zone-raid-step');
        if(!zone) return;
        zone.innerHTML = '';
        const activeRaids = Store.raids.filter(r => r.status === 'ACTIVE' && !r.isCampaign); // Campaign raids handled in War View

        activeRaids.forEach(r => {
            const step = r.steps.find(s => s.status === 'ACTIVE');
            if(!step) return;
            zone.innerHTML += `
            <div style="background:var(--bg-panel); border:2px solid var(--danger); border-radius:12px; padding:15px; margin-bottom:20px; position:relative; overflow:hidden;">
                <div style="position:absolute; top:0; left:0; width:100%; height:4px; background:rgba(255, 75, 75, 0.2);">
                   <div style="height:100%; background:var(--danger); width:${(r.steps.indexOf(step) / r.steps.length)*100}%;"></div>
                </div>

                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; margin-top:5px;">
                    <div style="font-size:0.7rem; color:var(--danger); font-weight:900; letter-spacing:1px;">ACTIVE OPERATION</div>
                    <div style="font-size:0.7rem; color:#fff; background:var(--danger); padding:2px 6px; border-radius:4px; font-weight:bold;">${r.size || 'NORMAL'}</div>
                </div>

                <div style="font-size:1.1rem; font-weight:900; color:#fff; margin-bottom:5px;">${escapeHTML(r.title)}</div>
                <div style="background:rgba(255, 75, 75, 0.1); padding:10px; border-radius:8px; border:1px dashed var(--danger); margin-bottom:15px; cursor:pointer;" onclick="UI.openStepControl('${r.id}', '${step.id}')">
                    <div style="font-size:0.65rem; color:var(--danger); font-weight:800; margin-bottom:3px;">CURRENT OBJECTIVE</div>
                    <div style="color:#fff; font-weight:bold; font-size:0.9rem;">${escapeHTML(step.txt)}</div>
                </div>

                <button class="btn-3d danger" style="width:100%;" onclick="Engine.advanceRaid('${r.id}')">
                    <i class="fas fa-skull"></i> EXECUTE STEP
                </button>
            </div>`;
        });
    },

    renderShop: () => {
        const sysZone = document.getElementById('shop-system');
        const listZone = document.getElementById('shop-list');
        if(!sysZone || !listZone) return;

        // System Tools
        sysZone.innerHTML = `
        <div class="game-row">
            <div style="flex:1;">
                <div style="font-weight:800;">Streak Freeze 🛡️</div>
                <div style="font-size:0.7rem; color:var(--text-muted);">Protect your streak for one day.</div>
            </div>
            <button class="btn-3d warning" onclick="Engine.buyItem('sys_freeze', 500, 'Streak Freeze')">500 G</button>
        </div>`;

        // Custom Items
        listZone.innerHTML = '';
        if(!Store.shopSections) Store.shopSections = ['General'];
        const organized = {};
        Store.shopSections.forEach(s => organized[s] = []);
        if(!Store.shopCustom) Store.shopCustom = [];
        Store.shopCustom.forEach(i => {
             if (i.section && organized[i.section]) organized[i.section].push(i);
             else {
                 if(!i.section) i.section = 'General';
                 if(organized['General']) organized['General'].push(i);
             }
        });

        const renderAisle = (title, items) => {
             if(items.length === 0) return '';
             let html = `<div style="margin-bottom:20px;">
                <div style="display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid #333; padding-bottom:5px; margin-bottom:10px;">
                    <div style="font-size:0.75rem; font-weight:900; color:var(--warning); text-transform:uppercase;">${escapeHTML(title)}</div>
                    ${title !== 'General' ? `<div style="cursor:pointer; color:#555;" onclick="Engine.deleteShopSection('${escapeHTML(title)}')">✖</div>` : ''}
                </div>`;
             items.forEach(item => {
                 html += `
                 <div class="game-row" style="border-color:var(--warning);">
                    <div style="flex:1; cursor:pointer;" onclick="UI.openShopDetails('${item.id}')">
                        <div style="font-weight:800; color:#fff;">${escapeHTML(item.title)}</div>
                        <div style="font-size:0.7rem; color:var(--text-muted);">Custom Reward</div>
                    </div>
                    <button class="btn-3d warning" onclick="Engine.buyItem('${item.id}', ${item.cost}, '${escapeHTML(item.title)}')">${item.cost} G</button>
                 </div>`;
             });
             html += `</div>`;
             return html;
        };

        Store.shopSections.forEach(sec => listZone.innerHTML += renderAisle(sec, organized[sec]));
        listZone.innerHTML += `<div style="text-align:center; margin-top:15px;">
            <button onclick="Engine.createShopSection()" style="background:transparent; border:1px dashed var(--warning); color:var(--warning); padding:8px 15px; border-radius:20px; font-size:0.7rem; cursor:pointer;">+ NEW AISLE</button>
        </div>`;
    },

    renderHistory: () => {
        const zone = document.getElementById('zone-history-list');
        const logZone = document.getElementById('zone-global-history');
        if(zone && Store.globalHistory) {
             // Basic list for hub
             zone.innerHTML = Store.globalHistory.slice(0, 10).map(l => 
                `<div style="font-size:0.75rem; border-bottom:1px solid #333; padding:8px 0; color:#aaa;">
                    <span style="color:#666; margin-right:5px;">${l.time}</span> ${l.msg}
                </div>`
             ).join('');
        }
        if(logZone && Store.globalHistory) {
             // Console log style for profile
             logZone.innerHTML = Store.globalHistory.map(l => {
                 let color = '#aaa';
                 if(l.tone === 'SUCCESS') color = 'var(--accent)';
                 if(l.tone === 'FAILURE') color = 'var(--danger)';
                 if(l.tone === 'NEUTRAL') color = '#fff';
                 return `<div style="margin-bottom:4px;">
                    <span style="color:#555;">[${l.time}]</span> <span style="color:${color};">${l.msg}</span>
                 </div>`;
             }).join('');
        }
    },

    renderWar: () => {
        const zone = document.getElementById('view-ops-war');
        if (!zone) return;
        const status = Engine.getWarStatus();
        const startStr = Store.season.startDate || "NOT SET";
        const currentWeek = status.currentWeek;
        const totalWeeks = 12;

        let gridHTML = '<div class="weeks-grid">';
