    renderWar: () => {
        const zone = document.getElementById('view-ops-war');
        if (!zone) return;
        const status = Engine.getWarStatus();
        const startStr = Store.season.startDate || "NOT SET";
        const currentWeek = status.currentWeek;
        const totalWeeks = 12;

        let gridHTML = '<div class="weeks-grid">';
        for (let i = 1; i <= totalWeeks; i++) {
            let stateClass = '';
            let label = `W${i}`;

            if (i < currentWeek) {
                stateClass = 'done';
            } else if (i === currentWeek) {
                stateClass = 'active';
            }

            gridHTML += `<div class="week-box ${stateClass}" onclick="UI.openWeekModal(${i})">${label}</div>`;
        }
        gridHTML += '</div>';

        zone.innerHTML = `
            <div class="section-title" style="color:var(--danger); border-color:var(--danger);">
                <i class="fas fa-biohazard"></i> WAR ROOM: WEEK ${currentWeek > 0 ? currentWeek : 'PRE-SEASON'}
            </div>

            <div style="background:var(--bg-panel); padding:15px; border-radius:12px; border:1px solid var(--danger); margin-bottom:20px; text-align:center;">
                <div style="font-size:0.8rem; color:var(--text-muted); font-weight:800; letter-spacing:2px; margin-bottom:5px;">SEASON START</div>
                <div style="font-size:1.2rem; font-weight:900; color:#fff; cursor:pointer;" onclick="Engine.setStartDate()">${startStr} 📅</div>
                <div style="font-size:0.7rem; color:#666; margin-top:5px;">Click date to calibrate</div>
            </div>

            <div style="margin-bottom:10px; font-size:0.75rem; color:var(--text-muted); font-weight:bold;">CAMPAIGN TIMELINE</div>
            ${gridHTML}

            <div style="margin-top:20px;">
                <button class="btn-3d danger" style="width:100%; padding:15px;" onclick="UI.openWarDayView()">
                    <i class="fas fa-map"></i> OPEN TACTICAL MAP (DAILY)
                </button>
            </div>
        `;
    },

    renderCalendar: () => {
        const grid = document.getElementById('calendar-body');
        const monthLabel = document.getElementById('cal-month-name');
        const yearLabel = document.getElementById('cal-year-num');
        if(!grid) return;

        const y = UI.calDate.getFullYear();
        const m = UI.calDate.getMonth();
        const firstDay = new Date(y, m, 1).getDay();
        const daysInMonth = new Date(y, m + 1, 0).getDate();

        monthLabel.innerText = UI.calDate.toLocaleString('default', { month: 'long' }).toUpperCase();
        yearLabel.innerText = y;

        grid.innerHTML = '';
        const today = new Date();

        // Empty slots
        for(let i=0; i<firstDay; i++) grid.innerHTML += '<div></div>';

        for(let d=1; d<=daysInMonth; d++) {
            const dateStr = new Date(y, m, d).toDateString();
            const isToday = (today.toDateString() === dateStr);

            // Check data for dots
            let dots = '';
            Store.habits.forEach(h => {
                if(h.history[dateStr] === 'DONE') dots += `<div class="cal-dot dot-habit-done"></div>`;
                if(h.history[dateStr] === 'MISSED') dots += `<div class="cal-dot dot-habit-miss"></div>`;
            });
            const tasksDone = Store.tasks.filter(t => t.status === 'DONE' && (!t.dueDate || t.dueDate === dateStr)).length; // Simplified logic for demo
            if(tasksDone > 0) dots += `<div class="cal-dot dot-task"></div>`;

            grid.innerHTML += `
            <div class="cal-cell ${isToday ? 'today' : ''}" onclick="UI.showDayDetails('${dateStr}')">
                <div class="cal-num">${d}</div>
                <div class="cal-dots">${dots}</div>
            </div>`;
        }
    },

    changeMonth: (delta) => {
        UI.calDate.setMonth(UI.calDate.getMonth() + delta);
        UI.renderCalendar();
    },

    showDayDetails: (dateStr) => {
        const box = document.getElementById('cal-day-details');
        const content = document.getElementById('cal-day-logs');
        box.classList.remove('hidden');
        content.innerHTML = `<div style="text-align:center; font-weight:bold; margin-bottom:10px;">${dateStr}</div>`;

        // Find logs for this day
        const logs = Store.globalHistory.filter(l => {
             // This is a rough check since logs only have Time. In a real app, logs would need full timestamps.
             // For this demo, we'll just show general habits history for that date.
             return false; 
        });

        // Show habits state for that day
        let found = false;
        Store.habits.forEach(h => {
            if(h.history[dateStr]) {
                found = true;
                const color = h.history[dateStr] === 'DONE' ? 'var(--accent)' : 'var(--danger)';
                content.innerHTML += `<div style="font-size:0.8rem; padding:4px 0; border-bottom:1px solid #333; color:${color};">
                    ${h.history[dateStr]} : ${h.title}
                </div>`;
            }
        });

        if(!found) content.innerHTML += `<div style="text-align:center; color:#555; font-size:0.8rem;">No Data Recorded</div>`;
    },

    openTrophy: (id) => {
        UI.tempTrophy = CONFIG.TROPHY_DB.find(t => t.id === id);
        if(!UI.tempTrophy) return;
        UI.tempTierIdx = 0; // Start at lowest
        // Find highest unlocked tier
        // This logic can be improved to show current progress. 
        // For simplicity, just opening the modal.
        UI.updateTrophyModal();
        document.getElementById('modal-trophy').classList.add('active');
    },

    navTrophy: (dir) => {
        if(!UI.tempTrophy) return;
        const max = UI.tempTrophy.tiers.length - 1;
        UI.tempTierIdx += dir;
        if(UI.tempTierIdx < 0) UI.tempTierIdx = 0;
        if(UI.tempTierIdx > max) UI.tempTierIdx = max;
        UI.updateTrophyModal();
    },

    updateTrophyModal: () => {
        const t = UI.tempTrophy;
        const tier = t.tiers[UI.tempTierIdx];
        const achieved = Store.achievements.find(a => a.title === t.title); // Simplification

        // Calculate progress based on type
        let currentVal = 0;
        if (t.type === 'GOLD') currentVal = Store.user.gold;
        else if (t.type === 'STREAK') currentVal = Store.user.streak;

        const pct = Math.min((currentVal / tier.val) * 100, 100);

        document.getElementById('tr-icon').innerText = t.icon;
        document.getElementById('tr-title').innerText = t.title;
        document.getElementById('tr-rank').innerText = tier.rank;
        document.getElementById('tr-quote').innerText = `"${tier.quote}"`;
        document.getElementById('tr-next').innerText = `${currentVal} / ${tier.val} ${t.type}`;
        document.getElementById('tr-bar').style.width = `${pct}%`;
    },

    openDetails: (id, type) => {
        let item;
        if (type === 'TASK') item = Store.tasks.find(i => i.id == id);
        else if (type === 'HABIT') item = Store.habits.find(i => i.id == id);

        if(!item) return;

        document.getElementById('dt-title').innerText = item.title;
        document.getElementById('dt-type').innerText = item.size || 'NORMAL';
        document.getElementById('dt-stats').innerText = (item.stats || []).join(', ');
        document.getElementById('dt-desc').innerText = item.desc || "No intel available.";

        if (item.linkedSkill) {
            document.getElementById('dt-skill-box').classList.remove('hidden');
            document.getElementById('dt-skill').innerText = item.linkedSkill;
        } else {
            document.getElementById('dt-skill-box').classList.add('hidden');
        }

        const rewards = CONFIG.HABIT_SIZES[item.size || 'NORMAL'];
        document.getElementById('dt-xp').innerText = rewards.xp;
        document.getElementById('dt-gold').innerText = rewards.gold;

        // Add Edit/Delete buttons dynamically to modal
        const modalContent = document.querySelector('#modal-details .modal-content');
        // Remove old buttons if any
        const oldBtns = document.getElementById('dt-actions');
        if(oldBtns) oldBtns.remove();

        const btnDiv = document.createElement('div');
        btnDiv.id = 'dt-actions';
        btnDiv.style.marginTop = '15px';
        btnDiv.style.display = 'flex';
        btnDiv.style.gap = '10px';

        btnDiv.innerHTML = `
            <button class="btn-3d neutral" style="flex:1;" onclick="Engine.openEditModal('${item.id}', '${type}')">EDIT</button>
            <button class="btn-3d" style="flex:1; background:#333; border-color:#555;" onclick="Engine.toggleArchive('${item.id}', '${type}')">${item.archived ? 'RESTORE' : 'ARCHIVE'}</button>
            <button class="btn-3d danger" style="flex:1;" onclick="Engine.delete${type === 'TASK' ? 'Task' : 'Habit'}('${item.id}')">DELETE</button>
        `;

        if(type === 'HABIT') {
             btnDiv.innerHTML += `<button class="btn-3d neutral" style="flex:1; margin-top:5px; width:100%;" onclick="Engine.moveHabit('${item.id}')">MOVE</button>`;
        }

        modalContent.appendChild(btnDiv);

        document.getElementById('modal-details').classList.add('active');
    },

    openShopDetails: (id) => {
        const item = Store.shopCustom.find(i => i.id == id);
        if(!item) return;
        document.getElementById('sh-dt-title').innerText = item.title;
        document.getElementById('sh-dt-desc').innerText = item.desc;
        document.getElementById('sh-dt-cost').innerText = item.cost + " G";

        const acts = document.getElementById('sh-actions');
        acts.innerHTML = `
            <button class="btn-3d warning" style="flex:1;" onclick="Engine.buyItem('${item.id}', ${item.cost}, '${escapeHTML(item.title)}')">BUY NOW</button>
            <button class="btn-3d neutral" style="flex:1;" onclick="Engine.moveShopItem('${item.id}')">MOVE</button>
        `;

        document.getElementById('modal-shop-details').classList.add('active');
    },

    openStreak: () => {
        document.getElementById('str-val').innerText = Store.user.streak;
        document.getElementById('str-target').innerText = `/ ${Store.user.streakMode === 'HARD' ? 500 : Store.user.streakMode === 'EASY' ? 300 : 400} XP`;

        const shieldCost = 500;
        const shieldBtn = document.getElementById('streak-shield-btn');
        const shieldStatus = document.getElementById('shield-status');
        const shieldCostTxt = document.getElementById('shield-cost');

        if(Store.user.streakShield) {
            shieldBtn.classList.add('shield-active');
            shieldStatus.innerText = "Active & Ready";
            shieldStatus.style.color = "var(--accent)";
            shieldCostTxt.innerText = "OWNED";
        } else {
            shieldBtn.classList.remove('shield-active');
            shieldStatus.innerText = "Not Equipped";
            shieldStatus.style.color = "var(--text-muted)";
            shieldCostTxt.innerText = `${shieldCost} G`;
        }

        document.getElementById('modal-streak').classList.add('active');
    },

    openStepControl: (raidId, stepId) => {
        const r = Store.raids.find(x => x.id == raidId);
        if(!r) return;
        const step = r.steps.find(s => s.id == stepId);
        if(!step) return;

        document.getElementById('step-raid-id').value = raidId;
        document.getElementById('step-id').value = stepId;

        document.getElementById('view-step-txt').innerText = step.txt;
        document.getElementById('view-step-desc').innerText = step.desc || 'No additional intel.';
        document.getElementById('view-step-diff').innerText = r.size || 'NORMAL';
        document.getElementById('view-step-skill').innerText = r.linkedSkill || 'NONE';

        document.getElementById('step-txt').value = step.txt;
        document.getElementById('step-desc').value = step.desc || '';

        UI.toggleStepEdit(false);
        document.getElementById('modal-step-control').classList.add('active');
    },

    toggleStepEdit: (isEdit) => {
        if(isEdit) {
            document.getElementById('step-view-mode').classList.add('hidden');
            document.getElementById('step-edit-mode').classList.remove('hidden');
        } else {
            document.getElementById('step-view-mode').classList.remove('hidden');
            document.getElementById('step-edit-mode').classList.add('hidden');
        }
    },

    switchHubTab: (tab) => {
        ['habits', 'logs', 'raids'].forEach(t => {
            document.getElementById(`view-${t}`).classList.add('hidden');
            const btn = document.getElementById(`tab-${t}`);
            btn.style.background = 'transparent';
            btn.style.color = 'var(--text-muted)';
        });

        document.getElementById(`view-${tab}`).classList.remove('hidden');
        const activeBtn = document.getElementById(`tab-${tab}`);
        activeBtn.style.background = 'var(--bg-app)';
        activeBtn.style.color = 'var(--text-main)';

        if(tab === 'raids') {
             const zone = document.getElementById('zone-raids-full');
             zone.innerHTML = '';
             Store.raids.forEach(r => {
                 const pct = (r.steps.filter(s=>s.status==='DONE').length / r.steps.length) * 100;
                 zone.innerHTML += `
                 <div class="game-row">
                    <div style="flex:1;">
                        <div style="font-weight:800;">${escapeHTML(r.title)}</div>
                        <div class="progress-container"><div class="progress-fill" style="width:${pct}%; background:var(--danger);"></div></div>
                    </div>
                    <button class="btn-3d danger" onclick="Engine.deleteRaid('${r.id}')">ABORT</button>
                 </div>`;
             });
        }
    },

    openWeekModal: (weekNum) => {
        document.getElementById('modal-week').classList.add('active');
        document.getElementById('week-title').innerText = `WEEK ${weekNum} INTEL`;
        UI.currentWeekEdit = weekNum;
        UI.renderWeekContent(weekNum);
    },

    renderWeekContent: (w) => {
        const zone = document.getElementById('week-content');
        zone.innerHTML = '';

        // Find tasks/raids assigned to this week
        const weekTasks = Store.tasks.filter(t => t.assignedDate && t.assignedDate.w === w);
        const weekSteps = []; 
        Store.raids.forEach(r => {
            r.steps.forEach(s => {
                if(s.assignedDate && s.assignedDate.w === w) {
                    weekSteps.push({ ...s, raidTitle: r.title, raidId: r.id });
                }
            });
        });

        if(weekTasks.length === 0 && weekSteps.length === 0) {
            zone.innerHTML = `<div style="text-align:center; padding:30px; color:#555;">NO OPS SCHEDULED</div>`;
            return;
        }

        // Render Days 1-7
        for(let d=1; d<=7; d++) {
            const dayTasks = weekTasks.filter(t => t.assignedDate.d === d);
            const daySteps = weekSteps.filter(s => s.assignedDate.d === d);

            if(dayTasks.length === 0 && daySteps.length === 0) continue;

            let html = `<div style="margin-bottom:15px; border:1px solid #333; border-radius:8px; padding:10px;">
                <div style="font-size:0.7rem; color:var(--text-muted); font-weight:800; margin-bottom:5px;">DAY ${d}</div>`;

            dayTasks.forEach(t => {
                html += `<div style="display:flex; justify-content:space-between; margin-bottom:5px; font-size:0.85rem;">
                    <span style="${t.status==='DONE' ? 'text-decoration:line-through; color:#555;' : 'color:#fff;'}">📄 ${escapeHTML(t.title)}</span>
                    ${t.status==='DONE' ? '✅' : '⬜'}
                </div>`;
            });

            daySteps.forEach(s => {
                html += `<div style="display:flex; justify-content:space-between; margin-bottom:5px; font-size:0.85rem;">
                    <span style="${s.status==='DONE' ? 'text-decoration:line-through; color:#555;' : 'color:var(--danger);'}">⚔️ ${escapeHTML(s.txt)}</span>
                    ${s.status==='DONE' ? '✅' : '⬜'}
                </div>`;
            });

            html += `</div>`;
            zone.innerHTML += html;
        }
    },

    showAssignMenu: () => {
         UI.closeModal('modal-week');
         UI.openNew('TASK'); 

         // Pre-fill week data
         if(UI.currentWeekEdit) {
             document.getElementById('inj-start-w').value = UI.currentWeekEdit;
             document.getElementById('inj-end-w').value = UI.currentWeekEdit;

             // Ensure fields are visible
             document.getElementById('war-range-inputs').classList.remove('hidden');
         }
    },

    openWarDayView: () => {
        document.getElementById('modal-war-day').classList.add('active');
        // Determine current week/day based on start date
        const status = Engine.getWarStatus();
        const totalDays = status.diffDays;

        let w = Math.floor(totalDays / 7) + 1;
        let d = (totalDays % 7) + 1; 

        // Handle pre-season
        if (totalDays < 0) { w = 1; d = 1; }

        UI.currentWarView = { w: w < 1 ? 1 : w, d: d < 1 ? 1 : d };
        UI.renderWarDayContent();
    },

    navWarDay: (dir) => {
        let { w, d } = UI.currentWarView;
        d += dir;
        if (d > 7) { d = 1; w++; }
        if (d < 1) { d = 7; w--; }
        if (w < 1) w = 1;

        UI.currentWarView = { w, d };
        UI.renderWarDayContent();
    },

    renderWarDayContent: () => {
        const { w, d } = UI.currentWarView;
        document.getElementById('war-day-title').innerHTML = `D${d} <span style="color:var(--text-muted)">|</span> W${w}`;

        const zone = document.getElementById('war-day-content');
        zone.innerHTML = '';

        // Filter content
        const tasks = Store.tasks.filter(t => t.assignedDate && t.assignedDate.w === w && t.assignedDate.d === d);
        const steps = [];
        Store.raids.forEach(r => {
             r.steps.forEach(s => {
                 if (s.assignedDate && s.assignedDate.w === w && s.assignedDate.d === d) {
                     steps.push({...s, raidId: r.id});
                 }
             });
        });

        if (tasks.length === 0 && steps.length === 0) {
            zone.innerHTML = `<div style="text-align:center; padding:50px; color:#555;">NO COMBAT DATA</div>`;
            return;
        }

        steps.forEach(s => {
             zone.innerHTML += `
             <div class="game-row" style="border-color:var(--danger);">
                <div style="flex:1;">
                    <div style="color:var(--danger); font-weight:800;">⚔️ RAID STEP</div>
                    <div style="font-size:0.9rem; color:#fff;">${escapeHTML(s.txt)}</div>
                </div>
                ${s.status !== 'DONE' ? 
                  `<button class="btn-3d danger" onclick="Engine.advanceRaid('${s.raidId}')">EXECUTE</button>` : 
                  `<div style="color:var(--accent); font-weight:900;">CLEARED</div>`}
             </div>`;
        });

        tasks.forEach(t => {
             zone.innerHTML += `
             <div class="game-row">
                <div style="flex:1;">
                    <div style="color:var(--text-muted); font-weight:800;">📄 TASK</div>
                    <div style="font-size:0.9rem; color:#fff;">${escapeHTML(t.title)}</div>
                </div>
                ${t.status !== 'DONE' ? 
                  `<button class="btn-3d success" onclick="Engine.completeTask('${t.id}')">DONE</button>` : 
                  `<div style="color:var(--accent); font-weight:900;">DONE</div>`}
             </div>`;
        });
    },

    showToast: (msg, type = 'neutral') => {
        const container = document.getElementById('toast-container');
        if(!container) return;
        const t = document.createElement('div');
        t.className = `toast ${type}`;
        t.innerHTML = msg; 
        container.appendChild(t);
        setTimeout(() => {
            t.style.animation = 'fadeOut 0.3s forwards';
            setTimeout(() => t.remove(), 300);
        }, 3000);
    }
};

// --- 6. BOOTSTRAP ---
function resetAllData() {
    if (confirm("⚠️ WARNING: FACTORY RESET\nThis will wipe all data permanently. Are you sure?")) {
        localStorage.removeItem('LifeOS_V7_Final');
        location.reload();
    }
}

