export const WarRoom: React.FC<Props> = ({ state }) => {
  const startStr = state.season.startDate;
  const start = new Date(startStr);
  const now = new Date();
  start.setHours(0,0,0,0);
  now.setHours(0,0,0,0);
  const diffTime = now.getTime() - start.getTime();
  const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
  let currentWeek = Math.floor(diffDays / 7) + 1;
  if(diffDays < 0) currentWeek = 0;

  const weeks = Array.from({length: 12}, (_, i) => i + 1);

  return (
    <div class="page active">
        <div style={{display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', height:'70vh', textAlign:'center'}}>

            <div class="section-title" style={{color:'var(--danger)', borderColor:'var(--danger)', width:'100%', justifyContent:'center'}}>
                <i class="fas fa-biohazard"></i> WAR ROOM: WEEK {currentWeek}
            </div>

            <div class="weeks-grid">
                {weeks.map(w => (
                    <div key={w} class={`week-box ${w < currentWeek ? 'done' : w === currentWeek ? 'active' : ''}`}>
                        W{w}
                    </div>
                ))}
            </div>

            <div style={{marginTop:'40px', border:'1px solid var(--danger)', padding:'15px 30px', borderRadius:'50px', color:'var(--danger)', background:'rgba(255, 0, 0, 0.05)'}}>
                CAMPAIGN ACTIVE
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import Swal from 'sweetalert2';
import { StatsBar } from './components/StatsBar';
import { BottomDock } from './components/BottomDock';
import { Profile } from './views/Profile';
import { Ops } from './views/Ops';
import { Hub } from './views/Hub';
import { Market } from './views/Market';
import { WarRoom } from './views/WarRoom';
import { GameState, StatKey, User, Task, Habit, Raid, Skill, ShopItem } from './types';

// Default Initial State
const INITIAL_STATE: GameState = {
  user: { lvl: 1, xp: 0, gold: 0, streak: 0, lastLogin: new Date().toDateString(), dailyXp: 0, streakMode: 'NORMAL', streakShield: false },
  season: { title: "OPERATION: IRON CLAD", startDate: "2026-01-01", goals: [] },
  stats: { STR:0, DIS:0, INT:0, CHR:0, EMT:0, PCE:0 },
  skills: [],
  tasks: [],
  habits: [],
  raids: [],
  achievements: [],
  shopCustom: [],
  globalHistory: [],
  habitSections: ['General'],
  shopSections: ['General']
};

export default function App() {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [view, setView] = useState<'PROFILE' | 'OPS' | 'HUB' | 'SHOP' | 'WAR'>('OPS');
  const [warMode, setWarMode] = useState(false);

  // Load Data
  useEffect(() => {
    const saved = localStorage.getItem('LifeOS_V7_Final');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState(prev => ({ ...prev, ...parsed }));
      } catch (e) {
        console.error("Failed to load save", e);
      }
    }
  }, []);

  // Auto-Save
  useEffect(() => {
    localStorage.setItem('LifeOS_V7_Final', JSON.stringify(state));
  }, [state]);

  // Actions
  const log = (msg: string, tone: 'SUCCESS' | 'FAILURE' | 'NEUTRAL') => {
      const time = new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
      setState(prev => ({
          ...prev,
          globalHistory: [{time, msg, tone}, ...prev.globalHistory].slice(0, 50)
      }));
  };

  const reward = (xp: number, gold: number) => {
      setState(prev => {
          let newUser = { ...prev.user, xp: prev.user.xp + xp, gold: prev.user.gold + gold, dailyXp: prev.user.dailyXp + xp };
          if(newUser.xp >= 1000) {
              newUser.lvl += 1;
              newUser.xp -= 1000;
              Swal.fire({ title: 'LEVEL UP!', icon: 'success', timer: 1500, showConfirmButton: false });
          }
          return { ...prev, user: newUser };
      });
  };

  const completeTask = (id: string) => {
      const task = state.tasks.find(t => t.id === id);
      if(!task) return;

      setState(prev => ({
          ...prev,
          tasks: prev.tasks.map(t => t.id === id ? { ...t, status: 'DONE' } : t),
          stats: { ...prev.stats, DIS: prev.stats.DIS + 1 }
      }));
      reward(50, 25);
      log(`Task Complete: ${task.title}`, 'SUCCESS');
  };

  const markHabit = (id: string, status: 'DONE' | 'MISSED') => {
      const today = new Date().toDateString();
      setState(prev => {
          const habit = prev.habits.find(h => h.id === id);
          if(!habit || habit.history[today]) return prev;

          const newHistory = { ...habit.history, [today]: status };
          const newStreak = status === 'DONE' ? habit.streak + 1 : 0;

          if(status === 'DONE') reward(30, 10);
          else log(`Missed Habit: ${habit.title}`, 'FAILURE');

          return {
              ...prev,
              habits: prev.habits.map(h => h.id === id ? { ...h, history: newHistory, streak: newStreak } : h)
          };
      });
  };

  const advanceRaid = (id: string) => {
      setState(prev => {
          const raid = prev.raids.find(r => r.id === id);
          if(!raid) return prev;

          const stepIndex = raid.steps.findIndex(s => s.status === 'ACTIVE');
          if(stepIndex === -1) return prev;

          const newSteps = [...raid.steps];
          newSteps[stepIndex].status = 'DONE';
          if(stepIndex + 1 < newSteps.length) newSteps[stepIndex + 1].status = 'ACTIVE';

          reward(100, 50);
          return {
              ...prev,
              raids: prev.raids.map(r => r.id === id ? { ...r, steps: newSteps } : r)
          };
      });
  };

  const buyItem = (id: string, cost: number, title: string) => {
      if(state.user.gold >= cost) {
          setState(prev => ({ ...prev, user: { ...prev.user, gold: prev.user.gold - cost } }));
          log(`Bought: ${title}`, 'NEUTRAL');
          Swal.fire({ title: 'PURCHASED', icon: 'success', timer: 1000, showConfirmButton: false });
      } else {
          Swal.fire({ title: 'INSUFFICIENT FUNDS', icon: 'error' });
      }
  };

  const addSkill = () => {
      Swal.fire({
          title: 'NEW SKILL',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newSkill: Skill = { id: Date.now().toString(), title: res.value, icon: '⚡', lvl: 1, xp: 0, maxXp: 100 };
              setState(prev => ({ ...prev, skills: [...prev.skills, newSkill] }));
          }
      });
  };

  const addTask = () => {
       Swal.fire({
          title: 'NEW TASK',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newTask: Task = { id: Date.now().toString(), title: res.value, status: 'ACTIVE', stats: ['DIS'], size: 'NORMAL' };
              setState(prev => ({ ...prev, tasks: [...prev.tasks, newTask] }));
          }
      });
  };

  const resetAll = () => {
      if(confirm("RESET SYSTEM?")) {
          setState(INITIAL_STATE);
          localStorage.removeItem('LifeOS_V7_Final');
      }
  };

  return (
    <div className="app-container">
        <StatsBar user={state.user} onOpenStreak={() => {}} onAddTask={addTask} />

        <div className="main-content">
            {view === 'PROFILE' && <Profile state={state} onAddSkill={addSkill} onReset={resetAll} />}
            {view === 'OPS' && <Ops state={state} onCompleteTask={completeTask} onAdvanceRaid={advanceRaid} onToggleWar={() => setWarMode(!warMode)} warMode={warMode} />}
