import React from 'react';
import { GameState, Task, Raid } from '../types';

interface Props {
  state: GameState;
  onCompleteTask: (id: string) => void;
  onAdvanceRaid: (id: string) => void;
  onToggleWar: () => void;
  warMode: boolean;
}

export const Ops: React.FC<Props> = ({ state, onCompleteTask, onAdvanceRaid, onToggleWar, warMode }) => {
  const activeTasks = state.tasks.filter(t => t.status === 'ACTIVE' && !t.archived && !t.isCampaign);
  const activeRaids = state.raids.filter(r => r.status === 'ACTIVE' && !r.isCampaign);

  const hasOps = activeTasks.length > 0 || activeRaids.length > 0;

  return (
    <div className="page active">
        <div style={{display:'flex', justifyContent:'space-between', alignItems:'center'}}>
             <div className="section-title"><i className="fas fa-crosshairs"></i> CURRENT OBJECTIVES</div>
             <button className={`btn-3d ${warMode ? 'danger' : 'neutral'}`} onClick={onToggleWar} style={{fontSize:'0.7rem', padding:'4px 10px'}}>
                {warMode ? 'WAR ACTIVE' : 'WAR OFF'}
             </button>
        </div>

        {activeRaids.map(r => {
             const step = r.steps.find(s => s.status === 'ACTIVE');
             if(!step) return null;
             return (
                <div key={r.id} style={{background:'var(--bg-panel)', border:'2px solid var(--danger)', borderRadius:'12px', padding:'15px', marginBottom:'20px', position:'relative', overflow:'hidden'}}>
                     <div style={{fontSize:'1.1rem', fontWeight:900, color:'#fff', marginBottom:'5px'}}>{r.title}</div>
                     <div style={{background:'rgba(255, 75, 75, 0.1)', padding:'10px', borderRadius:'8px', border:'1px dashed var(--danger)', marginBottom:'15px'}}>
                        <div style={{fontSize:'0.65rem', color:'var(--danger)', fontWeight:800}}>CURRENT OBJECTIVE</div>
                        <div style={{color:'#fff', fontWeight:'bold'}}>{step.txt}</div>
                     </div>
                     <button className="btn-3d danger" style={{width:'100%'}} onClick={() => onAdvanceRaid(r.id)}>EXECUTE STEP</button>
                </div>
             )
        })}

        {activeTasks.map(t => (
            <div key={t.id} className="game-row" style={{borderLeft:'4px solid var(--stat-int)'}}>
                <div style={{flex:1}}>
                    <div style={{fontWeight:800, fontSize:'0.9rem'}}>{t.title}</div>
                    <div style={{display:'flex', gap:'5px', marginTop:'5px'}}>
                        <span className="meta-tag tag-normal">{t.size}</span>
                    </div>
                </div>
                <button className="btn-3d success" style={{padding:'8px 14px'}} onClick={() => onCompleteTask(t.id)}>
                    <i className="fas fa-check"></i>
                </button>
            </div>
        ))}

        {!hasOps && (
            <div style={{textAlign:'center', padding:'40px 20px', opacity:0.6}}>
                <div style={{background:'rgba(88, 204, 2, 0.1)', width:'80px', height:'80px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 15px auto'}}>
                    <i className="fas fa-flag-checkered" style={{fontSize:'2.5rem', color:'var(--accent)'}}></i>
                </div>
                <div style={{fontWeight:800, fontSize:'1.2rem', marginBottom:'5px'}}>ALL CLEAR</div>
            </div>
        )}
    </div>
  );
};

import React, { useState } from 'react';
import { GameState, Habit } from '../types';

interface Props {
  state: GameState;
  onMarkHabit: (id: string, status: 'DONE' | 'MISSED') => void;
}

export const Hub: React.FC<Props> = ({ state, onMarkHabit }) => {
  const [tab, setTab] = useState<'HABITS' | 'LOGS'>('HABITS');
  const today = new Date().toDateString();
  const dayIndex = new Date().getDay();

  // Filter habits for today
  const activeHabits = state.habits.filter(h => 
      !h.archived && (h.activeDays ? h.activeDays.includes(dayIndex) : true)
  );

  return (
    <div className="page active">
        <div className="section-title"><i className="fas fa-layer-group"></i> PROTOCOL CENTER</div>

        <div style={{background:'var(--bg-panel)', padding:'4px', borderRadius:'12px', display:'flex', marginBottom:'15px', border:'2px solid var(--border)'}}>
            <div onClick={() => setTab('HABITS')} style={{flex:1, height:'40px', borderRadius:'8px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', fontWeight:800, background: tab==='HABITS' ? 'var(--bg-app)' : 'transparent', color: tab==='HABITS' ? 'var(--text-main)' : 'var(--text-muted)', cursor:'pointer'}}>HABITS</div>
            <div onClick={() => setTab('LOGS')} style={{flex:1, height:'40px', borderRadius:'8px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', fontWeight:800, background: tab==='LOGS' ? 'var(--bg-app)' : 'transparent', color: tab==='LOGS' ? 'var(--text-main)' : 'var(--text-muted)', cursor:'pointer'}}>LOGS</div>
        </div>

        {tab === 'HABITS' && (
            <div>
                {activeHabits.map(h => {
                    const status = h.history[today];
                    const isDone = status === 'DONE';
                    const isMissed = status === 'MISSED';

                    return (
                        <div key={h.id} className="habit-card" style={{borderColor: isDone ? 'var(--accent)' : isMissed ? 'var(--danger)' : 'var(--border)'}}>
                            <div style={{flex:1}}>
                                <div style={{fontWeight:800, fontSize:'0.95rem', color:'#fff'}}>{h.title}</div>
                                <div style={{fontSize:'0.7rem', color:'var(--text-muted)'}}>🔥 {h.streak}</div>
                            </div>
                            <div style={{display:'flex', gap:'8px'}}>
                                {!status ? (
                                    <>
                                        <button className="btn-3d danger" style={{padding:'6px 12px'}} onClick={() => onMarkHabit(h.id, 'MISSED')}>✖</button>
                                        <button className="btn-3d success" style={{padding:'6px 12px'}} onClick={() => onMarkHabit(h.id, 'DONE')}>✔</button>
                                    </>
                                ) : (
                                    <div style={{fontWeight:900, color: isDone ? 'var(--accent)' : 'var(--danger)'}}>
                                        {status}
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}

        {tab === 'LOGS' && (
            <div className="card" style={{fontFamily:'monospace', fontSize:'0.75rem'}}>
                {state.globalHistory.map((l, i) => (
                    <div key={i} style={{marginBottom:'4px', color: l.tone === 'SUCCESS' ? 'var(--accent)' : l.tone === 'FAILURE' ? 'var(--danger)' : '#aaa'}}>
                        [{l.time}] {l.msg}
                    </div>
                ))}
            </div>
        )}
    </div>
  );
};

import React from 'react';
import { GameState } from '../types';

interface Props {
  state: GameState;
  onBuy: (id: string, cost: number, title: string) => void;
}

export const Market: React.FC<Props> = ({ state, onBuy }) => {
  return (
    <div className="page active">
        <div className="section-title"><span><i className="fas fa-shopping-cart"></i> MARKET</span></div>

        <div style={{fontSize:'0.8rem', color:'var(--accent)', fontWeight:800, marginBottom:'10px'}}>SYSTEM TOOLS</div>
        <div className="game-row">
            <div style={{flex:1}}>
                <div style={{fontWeight:800}}>Streak Freeze 🛡️</div>
                <div style={{fontSize:'0.7rem', color:'var(--text-muted)'}}>Protect your streak.</div>
            </div>
            <button className="btn-3d warning" onClick={() => onBuy('sys_freeze', 500, 'Streak Freeze')}>500 G</button>
        </div>

        <div style={{fontSize:'0.8rem', color:'var(--warning)', fontWeight:800, margin:'20px 0 10px 0'}}>CUSTOM REWARDS</div>
        {state.shopCustom.map(item => (
            <div key={item.id} className="game-row" style={{borderColor:'var(--warning)'}}>
                <div style={{flex:1}}>
                    <div style={{fontWeight:800, color:'#fff'}}>{item.title}</div>
                    <div style={{fontSize:'0.7rem', color:'var(--text-muted)'}}>{item.cost} G</div>
                </div>
                <button className="btn-3d warning" onClick={() => onBuy(item.id, item.cost, item.title)}>BUY</button>
            </div>
        ))}
    </div>
