import React, { useState, useEffect } from 'react';
import Swal from 'sweetalert2';
import { StatsBar } from './components/StatsBar';
import { BottomDock } from './components/BottomDock';
import { Profile } from './views/Profile';
import { Ops } from './views/Ops';
import { Hub } from './views/Hub';
import { Market } from './views/Market';
import { WarRoom } from './views/WarRoom';
import { GameState, StatKey, User, Task, Habit, Raid, Skill, ShopItem } from './types';

// Default Initial State
const INITIAL_STATE: GameState = {
  user: { lvl: 1, xp: 0, gold: 0, streak: 0, lastLogin: new Date().toDateString(), dailyXp: 0, streakMode: 'NORMAL', streakShield: false },
  season: { title: "OPERATION: IRON CLAD", startDate: "2026-01-01", goals: [] },
  stats: { STR:0, DIS:0, INT:0, CHR:0, EMT:0, PCE:0 },
  skills: [],
  tasks: [],
  habits: [],
  raids: [],
  achievements: [],
  shopCustom: [],
  globalHistory: [],
  habitSections: ['General'],
  shopSections: ['General']
};

export default function App() {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [view, setView] = useState<'PROFILE' | 'OPS' | 'HUB' | 'SHOP' | 'WAR'>('OPS');
  const [warMode, setWarMode] = useState(false);
  const [loaded, setLoaded] = useState(false);

  // Load Data with Safety Check
  useEffect(() => {
    const saved = localStorage.getItem('LifeOS_V7_Final');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Deep merge safe-guard to prevent crashes if old data is missing keys
        setState(prev => ({
            ...prev,
            ...parsed,
            user: { ...prev.user, ...(parsed.user || {}) },
            stats: { ...prev.stats, ...(parsed.stats || {}) },
            // Ensure arrays are actually arrays
            tasks: Array.isArray(parsed.tasks) ? parsed.tasks : prev.tasks,
            habits: Array.isArray(parsed.habits) ? parsed.habits : prev.habits,
            raids: Array.isArray(parsed.raids) ? parsed.raids : prev.raids,
            skills: Array.isArray(parsed.skills) ? parsed.skills : prev.skills,
            achievements: Array.isArray(parsed.achievements) ? parsed.achievements : prev.achievements,
            shopCustom: Array.isArray(parsed.shopCustom) ? parsed.shopCustom : prev.shopCustom,
            globalHistory: Array.isArray(parsed.globalHistory) ? parsed.globalHistory : prev.globalHistory,
        }));
      } catch (e) {
        console.error("Failed to load save", e);
      }
    }
    setLoaded(true);
  }, []);

  // Auto-Save
  useEffect(() => {
    if (loaded) {
        localStorage.setItem('LifeOS_V7_Final', JSON.stringify(state));
    }
  }, [state, loaded]);

  // Actions
  const log = (msg: string, tone: 'SUCCESS' | 'FAILURE' | 'NEUTRAL') => {
      const time = new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});
      setState(prev => ({
          ...prev,
          globalHistory: [{time, msg, tone}, ...prev.globalHistory].slice(0, 50)
      }));
  };

  const reward = (xp: number, gold: number) => {
      setState(prev => {
          let newUser = { ...prev.user, xp: prev.user.xp + xp, gold: prev.user.gold + gold, dailyXp: prev.user.dailyXp + xp };
          if(newUser.xp >= 1000) {
              newUser.lvl += 1;
              newUser.xp -= 1000;
              Swal.fire({ title: 'LEVEL UP!', icon: 'success', timer: 1500, showConfirmButton: false });
          }
          return { ...prev, user: newUser };
      });
  };

  const completeTask = (id: string) => {
      const task = state.tasks.find(t => t.id === id);
      if(!task) return;

      setState(prev => ({
          ...prev,
          tasks: prev.tasks.map(t => t.id === id ? { ...t, status: 'DONE' } : t),
          stats: { ...prev.stats, DIS: prev.stats.DIS + 1 }
      }));
      reward(50, 25);
      log(`Task Complete: ${task.title}`, 'SUCCESS');
  };

  const markHabit = (id: string, status: 'DONE' | 'MISSED') => {
      const today = new Date().toDateString();
      setState(prev => {
          const habit = prev.habits.find(h => h.id === id);
          if(!habit || habit.history[today]) return prev;

          const newHistory = { ...habit.history, [today]: status };
          const newStreak = status === 'DONE' ? habit.streak + 1 : 0;

          if(status === 'DONE') reward(30, 10);
          else log(`Missed Habit: ${habit.title}`, 'FAILURE');

          return {
              ...prev,
              habits: prev.habits.map(h => h.id === id ? { ...h, history: newHistory, streak: newStreak } : h)
          };
      });
  };

  const advanceRaid = (id: string) => {
      setState(prev => {
          const raid = prev.raids.find(r => r.id === id);
          if(!raid) return prev;

          const stepIndex = raid.steps.findIndex(s => s.status === 'ACTIVE');
          if(stepIndex === -1) return prev;

          const newSteps = [...raid.steps];
          newSteps[stepIndex].status = 'DONE';
          if(stepIndex + 1 < newSteps.length) newSteps[stepIndex + 1].status = 'ACTIVE';

          reward(100, 50);
          return {
              ...prev,
              raids: prev.raids.map(r => r.id === id ? { ...r, steps: newSteps } : r)
          };
      });
  };

  const buyItem = (id: string, cost: number, title: string) => {
      if(state.user.gold >= cost) {
          setState(prev => ({ ...prev, user: { ...prev.user, gold: prev.user.gold - cost } }));
          log(`Bought: ${title}`, 'NEUTRAL');
          Swal.fire({ title: 'PURCHASED', icon: 'success', timer: 1000, showConfirmButton: false });
      } else {
          Swal.fire({ title: 'INSUFFICIENT FUNDS', icon: 'error' });
      }
  };

  const addSkill = () => {
      Swal.fire({
          title: 'NEW SKILL',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newSkill: Skill = { id: Date.now().toString(), title: res.value, icon: '⚡', lvl: 1, xp: 0, maxXp: 100 };
              setState(prev => ({ ...prev, skills: [...prev.skills, newSkill] }));
          }
      });
  };

  const addTask = () => {
       Swal.fire({
          title: 'NEW TASK',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newTask: Task = { id: Date.now().toString(), title: res.value, status: 'ACTIVE', stats: ['DIS'], size: 'NORMAL' };
              setState(prev => ({ ...prev, tasks: [...prev.tasks, newTask] }));
          }
      });
  };

  const resetAll = () => {
      if(confirm("RESET SYSTEM?")) {
          setState(INITIAL_STATE);
          localStorage.removeItem('LifeOS_V7_Final');
      }
  };

  if (!loaded) return <div style={{display:'flex', justifyContent:'center', alignItems:'center', height:'100vh', color:'var(--accent)'}}>INITIALIZING SYSTEM...</div>;

  return (
    <div className="app-container">
        <StatsBar user={state.user} onOpenStreak={() => {}} onAddTask={addTask} />

        <div className="main-content">
            {view === 'PROFILE' && <Profile state={state} onAddSkill={addSkill} onReset={resetAll} />}
            {view === 'OPS' && <Ops state={state} onCompleteTask={completeTask} onAdvanceRaid={advanceRaid} onToggleWar={() => setWarMode(!warMode)} warMode={warMode} />}
            {view === 'HUB' && <Hub state={state} onMarkHabit={markHabit} />}
            {view === 'SHOP' && <Market state={state} onBuy={buyItem} />}
            {view === 'WAR' && <WarRoom state={state} />}
            {warMode && view === 'OPS' && <div style={{position:'fixed', bottom:'100px', left:'50%', transform:'translateX(-50%)', color:'red', fontWeight:'bold', animation:'pulse 1s infinite'}}>WAR ACTIVE</div>}
        </div>

        <BottomDock activeView={view} onNav={(v) => {
             if(warMode && v === 'OPS') setView('WAR'); // Redirect to War Room if mode active
             else setView(v);
        }} />
    </div>
  );
}

/* --- 1. GAMIFIED THEME VARIABLES --- */
:root {
    /* Core Colors */
    --bg-app: #131422;
    --bg-panel: #202136;
    --bg-dim: rgba(255,255,255,0.05);
    --border: #2d2f45;

    /* Typography */
    --text-main: #ffffff;
    --text-muted: #8b9bb4;

    /* UI Accents */
    --accent: #58cc02;        /* Success/Green */
    --accent-shadow: #46a302; 

    --danger: #ff4b4b;        /* Error/Combat/Red */
    --danger-shadow: #d42a2a;

    --warning: #ffc800;       /* Gold/Rare/Yellow */
    --warning-shadow: #e5b400;

    --inject: #ce82ff;        /* Magic/Skill/Purple */
    --inject-shadow: #a561d1;

    /* RPG Stat Colors */
    --stat-str: #ff9600;      /* Strength */
    --stat-dis: #2b70c9;      /* Discipline */
    --stat-int: #1cb0f7;      /* Intelligence */
    --stat-chr: #ff4b4b;      /* Charisma */
    --stat-emt: #ce82ff;      /* Emotional */
    --stat-pce: #89e219;      /* Peace */

    /* Dimensions */
    --radius-l: 16px;
    --radius-m: 12px;
    --radius-s: 8px;
}

/* Global Reset */
* { box-sizing: border-box; -webkit-tap-highlight-color: transparent; outline: none; }

html, body, #root {
    margin: 0;
    padding: 0;
    height: 100%;
    width: 100%;
    overflow: hidden; /* App container handles scrolling */
}

body { 
    background-color: var(--bg-app); 
    color: var(--text-main); 
    font-family: "Nunito", "Segoe UI", Tahoma, sans-serif;
    direction: ltr;
}

.app-container {
    display: flex;
    flex-direction: column;
    height: 100vh;
    width: 100vw;
    position: relative;
    background-color: var(--bg-app);
}

.main-content { 
    flex: 1; 
    overflow-y: auto; 
    padding: 85px 16px 100px 16px; /* Top padding for StatsBar, Bottom for Dock */
    -webkit-overflow-scrolling: touch;
}

/* Animations */
@keyframes popIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
@keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.5; } 100% { opacity: 1; } }

.page { 
    display: none; 
    animation: popIn 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
}
.page.active { display: block; }

.section-title {
    font-size: 0.85rem; 
    color: var(--text-muted); 
    font-weight: 800;
    text-transform: uppercase; 
    letter-spacing: 1px; 
    margin: 25px 0 10px 0;
    padding-left: 10px; 
    border-left: 4px solid var(--border);
    display: flex; align-items: center; gap: 8px;
}

/* --- COMPONENTS: BUTTONS & HUD --- */
.status-bar {
    height: 70px; background: var(--bg-app); 
    border-bottom: 2px solid var(--border);
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 16px; 
    position: fixed; top: 0; left: 0; width: 100%; z-index: 1000;
}

.hud-container { display: flex; gap: 8px; align-items: center; }

.hud-badge {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 10px; border-radius: var(--radius-m);
    font-weight: 800; font-size: 0.85rem;
    border-bottom: 3px solid rgba(0,0,0,0.2);
}

.hud-gold { background: var(--bg-panel); color: var(--warning); border: 1px solid var(--warning); }
.hud-streak { background: var(--bg-panel); color: var(--danger); border: 1px solid var(--danger); }
.hud-lvl { background: var(--bg-panel); color: var(--stat-int); border: 1px solid var(--stat-int); }

.btn-3d {
    background-color: var(--inject); color: #fff; border: none;
    border-radius: var(--radius-m); padding: 8px 16px;
    font-weight: 800; font-size: 0.9rem; cursor: pointer;
    box-shadow: 0 4px 0 var(--inject-shadow); transition: all 0.1s;
    display: flex; align-items: center; justify-content: center; gap: 8px;
    text-transform: uppercase; letter-spacing: 0.5px;
}
.btn-3d:active { transform: translateY(4px); box-shadow: 0 0 0 var(--inject-shadow); }
.btn-3d.danger { background-color: var(--danger); box-shadow: 0 4px 0 var(--danger-shadow); }
.btn-3d.success { background-color: var(--accent); box-shadow: 0 4px 0 var(--accent-shadow); }
.btn-3d.warning { background-color: var(--warning); box-shadow: 0 4px 0 var(--warning-shadow); color: #000; }
.btn-3d.neutral { background-color: var(--bg-panel); box-shadow: 0 4px 0 var(--border); border: 1px solid var(--border); color: var(--text-muted); }

/* --- CARDS & LISTS --- */
.card {
    background: var(--bg-panel);
    border: 2px solid var(--border);
    border-radius: var(--radius-l);
    padding: 16px; margin-bottom: 16px;
}

.game-row {
    display: flex; justify-content: space-between; align-items: center;
    background: var(--bg-panel);
    border: 2px solid var(--border);
    border-bottom: 4px solid var(--border);
    border-radius: var(--radius-m);
    padding: 16px; margin-bottom: 12px;
    transition: transform 0.1s;
}
.game-row:active { transform: translateY(2px); border-bottom-width: 2px; }

.meta-tag {
    font-size: 0.65rem; font-weight: 800;
    padding: 4px 8px; border-radius: 6px;
    text-transform: uppercase; margin-right: 5px;
    display: inline-block;
}
.tag-normal { background: rgba(28, 176, 246, 0.15); color: var(--stat-int); }
.tag-big { background: rgba(255, 75, 75, 0.15); color: var(--danger); }
.tag-skill { background: rgba(206, 130, 255, 0.15); color: var(--inject); border: 1px solid var(--inject); }

/* --- HABIT CARDS --- */
.habit-card {
    display: flex; align-items: center; gap: 12px;
    background: var(--bg-panel);
    border: 2px solid var(--border);
    border-radius: var(--radius-m);
    padding: 12px; margin-bottom: 10px;
    transition: all 0.2s ease;
    position: relative; overflow: hidden;
}

/* --- NAV & PROGRESS --- */
.bottom-nav {
    position: fixed; bottom: 0; width: 100%; height: 80px;
    background: var(--bg-app); border-top: 2px solid var(--border);
    display: flex; justify-content: space-around; align-items: center;
    z-index: 100; padding-bottom: 15px;
}
.nav-item {
    display: flex; justify-content: center; align-items: center;
    width: 50px; height: 50px; border-radius: 16px;
    color: var(--text-muted); font-size: 1.5rem;
    cursor: pointer; transition: all 0.2s;
    border: 2px solid transparent; border-bottom: 4px solid transparent;
}
.nav-item.active {
    background: rgba(28, 176, 246, 0.15); color: var(--stat-int);
    border-color: rgba(28, 176, 246, 0.3); border-bottom-width: 4px;
}
.progress-container { height: 10px; background: var(--bg-app); border-radius: 5px; overflow: hidden; margin-top: 8px; }
.progress-fill { height: 100%; transition: width 0.5s ease; border-radius: 5px; }

/* --- WEEKS GRID --- */
.weeks-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
    background: rgba(0,0,0,0.3);
    padding: 10px;
    border-radius: 8px;
    border: 1px solid var(--border);
    margin-top: 10px;
}

.week-box {
    background: var(--bg-app);
    border: 1px solid #333;
    border-radius: 6px;
