              raids: prev.raids.map(r => r.id === id ? { ...r, steps: newSteps } : r)
          };
      });
  };

  const buyItem = (id: string, cost: number, title: string) => {
      if(state.user.gold >= cost) {
          setState(prev => ({ ...prev, user: { ...prev.user, gold: prev.user.gold - cost } }));
          log(`Bought: ${title}`, 'NEUTRAL');
          Swal.fire({ title: 'PURCHASED', icon: 'success', timer: 1000, showConfirmButton: false });
      } else {
          Swal.fire({ title: 'INSUFFICIENT FUNDS', icon: 'error' });
      }
  };

  const addSkill = () => {
      Swal.fire({
          title: 'NEW SKILL',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newSkill: Skill = { id: Date.now().toString(), title: res.value, icon: '⚡', lvl: 1, xp: 0, maxXp: 100 };
              setState(prev => ({ ...prev, skills: [...prev.skills, newSkill] }));
          }
      });
  };

  const addTask = () => {
       Swal.fire({
          title: 'NEW TASK',
          input: 'text',
          background: '#000',
          color: '#fff'
      }).then(res => {
          if(res.value) {
              const newTask: Task = { id: Date.now().toString(), title: res.value, status: 'ACTIVE', stats: ['DIS'], size: 'NORMAL' };
              setState(prev => ({ ...prev, tasks: [...prev.tasks, newTask] }));
          }
      });
  };

  const resetAll = () => {
      if(confirm("RESET SYSTEM?")) {
          localStorage.removeItem('LifeOS_V7_Final');
          window.location.reload();
      }
  };

  if (!loaded) return <div style={{display:'flex', justifyContent:'center', alignItems:'center', height:'100vh', color:'var(--accent)'}}>LOADING SYSTEM...</div>;

  // Fallback Error UI
  if (error) {
      return (
          <div style={{display:'flex', flexDirection:'column', justifyContent:'center', alignItems:'center', height:'100vh', color:'var(--danger)', padding:'20px', textAlign:'center'}}>
              <i className="fas fa-exclamation-triangle" style={{fontSize:'3rem', marginBottom:'20px'}}></i>
              <h3>SYSTEM CRITICAL ERROR</h3>
              <p>{error}</p>
              <button className="btn-3d danger" onClick={resetAll} style={{marginTop:'20px'}}>FACTORY RESET</button>
          </div>
      );
  }

  return (
    <div className="app-container">
        <StatsBar user={state.user} onOpenStreak={() => {}} onAddTask={addTask} />

        <div className="main-content">
            {view === 'PROFILE' && <Profile state={state} onAddSkill={addSkill} onReset={resetAll} />}
            {view === 'OPS' && <Ops state={state} onCompleteTask={completeTask} onAdvanceRaid={advanceRaid} onToggleWar={() => setWarMode(!warMode)} warMode={warMode} />}
            {view === 'HUB' && <Hub state={state} onMarkHabit={markHabit} />}
            {view === 'SHOP' && <Market state={state} onBuy={buyItem} />}
            {view === 'WAR' && <WarRoom state={state} />}
            {warMode && view === 'OPS' && <div style={{position:'fixed', bottom:'100px', left:'50%', transform:'translateX(-50%)', color:'red', fontWeight:'bold', animation:'pulse 1s infinite'}}>WAR ACTIVE</div>}
        </div>

        <BottomDock activeView={view} onNav={(v) => {
             if(warMode && v === 'OPS') setView('WAR');
             else setView(v);
        }} />
    </div>
  );
}

