interface User {
  lvl: number;
  xp: number;
  gold: number;
  streak: number;
  dailyXp: number;
  lastLogin: string;
  streakMode: 'EASY' | 'NORMAL' | 'HARD';
  streakDoneToday: boolean;
}

interface Task {
  id: string;
  title: string;
  desc?: string;
  status: 'ACTIVE' | 'DONE';
  size: 'SMALL' | 'NORMAL' | 'BIG';
  stats: string[];
  archived?: boolean;
}

interface Habit {
  id: string;
  title: string;
  streak: number;
  history: Record<string, 'DONE' | 'MISS'>;
  size: 'SMALL' | 'NORMAL' | 'BIG';
  stats: string[];
  archived?: boolean;
}

interface StoreData {
  user: User;
  tasks: Task[];
  habits: Habit[];
  stats: Record<string, number>;
  globalHistory: { time: string; msg: string; type: string }[];
}

// --- CONSTANTS ---
const XP_TARGETS = { EASY: 300, NORMAL: 400, HARD: 500 };
const LVL_THRESHOLD = 1000;
const REWARDS = {
  SMALL: { xp: 20, gold: 5 },
  NORMAL: { xp: 50, gold: 10 },
  BIG: { xp: 100, gold: 20 }
};

const App: React.FC = () => {
  const [view, setView] = useState<'profile' | 'ops' | 'hub' | 'shop'>('ops');
  const [store, setStore] = useState<StoreData>(() => {
    const saved = localStorage.getItem('LifeOS_V7_Final');
    if (saved) return JSON.parse(saved);
    return {
      user: {
        lvl: 1, xp: 0, gold: 0, streak: 0, dailyXp: 0,
        lastLogin: new Date().toDateString(),
        streakMode: 'NORMAL',
        streakDoneToday: false
      },
      tasks: [],
      habits: [],
      stats: { STR: 0, INT: 0, DIS: 0, CHR: 0, EMT: 0, PCE: 0 },
      globalHistory: []
    };
  });

  // Save to localStorage whenever store changes
  useEffect(() => {
    localStorage.setItem('LifeOS_V7_Final', JSON.stringify(store));
  }, [store]);

  // Daily Reset Check
  useEffect(() => {
    const today = new Date().toDateString();
    if (store.user.lastLogin !== today) {
      setStore(prev => {
        const streakLost = !prev.user.streakDoneToday && prev.user.streak > 0;
        return {
          ...prev,
          user: {
            ...prev.user,
            lastLogin: today,
            dailyXp: 0,
            streakDoneToday: false,
            streak: streakLost ? 0 : prev.user.streak
          },
          globalHistory: [
            { time: new Date().toLocaleTimeString(), msg: streakLost ? "💀 Streak Lost!" : "🌅 New Day Started", type: 'SYSTEM' },
            ...prev.globalHistory
          ].slice(0, 50)
        };
      });
    }
  }, []);

  // --- ACTIONS ---
  const rewardUser = (xp: number, gold: number) => {
    setStore(prev => {
      let newXp = prev.user.xp + xp;
      let newLvl = prev.user.lvl;
      let newDailyXp = prev.user.dailyXp + xp;
      let newStreak = prev.user.streak;
      let newStreakDone = prev.user.streakDoneToday;

      // Check Daily Streak
      const target = XP_TARGETS[prev.user.streakMode];
      if (newDailyXp >= target && !newStreakDone) {
        newStreak++;
        newStreakDone = true;
      }

      // Check Level Up
      if (newXp >= LVL_THRESHOLD) {
        newLvl++;
        newXp -= LVL_THRESHOLD;
      }

      return {
        ...prev,
        user: { ...prev.user, xp: newXp, lvl: newLvl, gold: prev.user.gold + gold, dailyXp: newDailyXp, streak: newStreak, streakDoneToday: newStreakDone }
      };
    });
  };

  const completeTask = (id: string) => {
    const task = store.tasks.find(t => t.id === id);
    if (!task) return;

    const reward = REWARDS[task.size];
    rewardUser(reward.xp, reward.gold);

    setStore(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === id ? { ...t, status: 'DONE' } : t),
      globalHistory: [{ time: new Date().toLocaleTimeString(), msg: `✅ Task Completed: ${task.title}`, type: 'TASK' }, ...prev.globalHistory].slice(0, 50)
    }));
  };

  const markHabit = (id: string, status: 'DONE' | 'MISS') => {
    const habit = store.habits.find(h => h.id === id);
    if (!habit) return;

    const today = new Date().toDateString();
    if (habit.history[today]) return;

    if (status === 'DONE') {
      const reward = REWARDS[habit.size];
      rewardUser(reward.xp, reward.gold);
    }

    setStore(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? {
        ...h,
        streak: status === 'DONE' ? h.streak + 1 : 0,
        history: { ...h.history, [today]: status }
      } : h),
      globalHistory: [{ time: new Date().toLocaleTimeString(), msg: `${status === 'DONE' ? '🔥' : '❌'} Habit: ${habit.title}`, type: 'HABIT' }, ...prev.globalHistory].slice(0, 50)
    }));
  };

  const addNewItem = (type: 'TASK' | 'HABIT') => {
    // Basic modal implementation via SweetAlert for now to keep it standard
    // @ts-ignore
    Swal.fire({
      title: `ADD NEW ${type}`,
      html: `
        <input id="swal-title" class="swal2-input" placeholder="Title">
        <select id="swal-size" class="swal2-input">
          <option value="SMALL">EASY</option>
          <option value="NORMAL" selected>NORMAL</option>
          <option value="BIG">HARD</option>
        </select>
      `,
      showCancelButton: true,
      confirmButtonText: 'DEPLOY',
      preConfirm: () => {
        const title = (document.getElementById('swal-title') as HTMLInputElement).value;
        const size = (document.getElementById('swal-size') as HTMLSelectElement).value;
        return { title, size };
      }
    }).then((result: any) => {
      if (result.isConfirmed && result.value.title) {
        const newItem = {
          id: Date.now().toString(),
          title: result.value.title,
          size: result.value.size as 'SMALL' | 'NORMAL' | 'BIG',
          status: 'ACTIVE',
          stats: ['DIS'],
          history: {},
          streak: 0
        };

        setStore(prev => ({
          ...prev,
          [type === 'TASK' ? 'tasks' : 'habits']: [...prev[type === 'TASK' ? 'tasks' : 'habits'], newItem]
        }));
      }
    });
  };

  // --- VIEWS ---
  const renderOps = () => {
    const activeTasks = store.tasks.filter(t => t.status === 'ACTIVE');
    return (
      <div className="page-transition">
        <div className="section-title"><i className="fas fa-crosshairs"></i> CURRENT OBJECTIVES</div>
        {activeTasks.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px', opacity: 0.5 }}>
            <i className="fas fa-check-double" style={{ fontSize: '3rem', marginBottom: '10px' }}></i>
            <p>ALL CLEAR</p>
          </div>
        ) : (
          activeTasks.map(t => (
            <div key={t.id} className="game-row">
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '0.7rem', color: 'var(--stat-int)', fontWeight: 800 }}>TASK | {t.size}</div>
                <div style={{ fontWeight: 700 }}>{t.title}</div>
              </div>
              <button className="btn-3d success" onClick={() => completeTask(t.id)}><i className="fas fa-check"></i></button>
            </div>
          ))
        )}
      </div>
    );
  };

  const renderHub = () => {
    const today = new Date().toDateString();
    return (
      <div className="page-transition">
        <div className="section-title"><i className="fas fa-layer-group"></i> PROTOCOL CENTER</div>
        <button className="btn-3d" style={{ width: '100%', marginBottom: '20px' }} onClick={() => addNewItem('HABIT')}>
          <i className="fas fa-plus"></i> NEW HABIT
        </button>
        {store.habits.map(h => {
          const status = h.history[today];
          return (
            <div key={h.id} className="game-row" style={{ opacity: status ? 0.6 : 1 }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: '0.7rem', color: 'var(--accent)', fontWeight: 800 }}>HABIT | STREAK: {h.streak}</div>
                <div style={{ fontWeight: 700 }}>{h.title}</div>
              </div>
              {!status ? (
                <div style={{ display: 'flex', gap: '5px' }}>
                  <button className="btn-3d success" onClick={() => markHabit(h.id, 'DONE')}><i className="fas fa-check"></i></button>
                  <button className="btn-3d danger" onClick={() => markHabit(h.id, 'MISS')}><i className="fas fa-times"></i></button>
                </div>
              ) : (
                <div style={{ fontWeight: 800, color: status === 'DONE' ? 'var(--accent)' : 'var(--danger)' }}>{status}</div>
              )}
            </div>
          );
        })}
      </div>
    );
  };

  const renderProfile = () => {
    return (
      <div className="page-transition">
        <div className="section-title"><i className="fas fa-brain"></i> ATTRIBUTE MATRIX</div>
        <div className="card">
          {Object.entries(store.stats).map(([stat, val]) => (
            <div key={stat} style={{ marginBottom: '12px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.8rem', fontWeight: 800 }}>
                <span>{stat}</span>
                <span>{val.toFixed(1)}</span>
              </div>
              <div className="progress-container">
                <div className="progress-fill" style={{ width: `${Math.min(100, (val / 50) * 100)}%`, backgroundColor: `var(--stat-${stat.toLowerCase()})` }}></div>
              </div>
            </div>
          ))}
        </div>
        <div className="section-title">KERNEL LOGS</div>
        <div className="card" style={{ maxHeight: '200px', overflowY: 'auto', fontSize: '0.75rem', fontFamily: 'monospace' }}>
          {store.globalHistory.map((log, i) => (
            <div key={i} style={{ marginBottom: '5px', borderLeft: '2px solid #555', paddingLeft: '8px' }}>
              <span style={{ color: 'var(--text-muted)' }}>[{log.time}]</span> {log.msg}
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderShop = () => {
    return (
      <div className="page-transition">
        <div className="section-title"><i className="fas fa-shopping-cart"></i> MARKET</div>
        <div style={{ textAlign: 'center', padding: '40px', opacity: 0.5 }}>
          <i className="fas fa-store-slash" style={{ fontSize: '3rem', marginBottom: '10px' }}></i>
          <p>MARKET OFFLINE</p>
          <p style={{ fontSize: '0.8rem' }}>Gather more gold to unlock indulgence protocols.</p>
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="status-bar">
        <div className="hud-container">
          <div className="hud-badge hud-lvl"><i className="fas fa-crown"></i> <span>{store.user.lvl}</span></div>
          <div className="hud-badge hud-gold"><i className="fas fa-coins"></i> <span>{store.user.gold}</span></div>
          <div className="hud-badge hud-streak"><i className="fas fa-fire"></i> <span>{store.user.streak}</span></div>
        </div>
        <button className="btn-3d" onClick={() => addNewItem('TASK')}>
          <i className="fas fa-plus"></i> ADD
        </button>
      </div>

      <div className="main-content">
        {view === 'ops' && renderOps()}
        {view === 'hub' && renderHub()}
        {view === 'profile' && renderProfile()}
        {view === 'shop' && renderShop()}
      </div>

      <nav className="bottom-nav">
        <div className={`nav-item ${view === 'profile' ? 'active' : ''}`} onClick={() => setView('profile')}><i className="fas fa-user-astronaut"></i></div>
        <div className={`nav-item ${view === 'hub' ? 'active' : ''}`} onClick={() => setView('hub')}><i className="fas fa-chart-line"></i></div>
        <div className={`nav-item ${view === 'ops' ? 'active' : ''}`} onClick={() => setView('ops')}><i className="fas fa-crosshairs"></i></div>
        <div className={`nav-item ${view === 'shop' ? 'active' : ''}`} onClick={() => setView('shop')}><i className="fas fa-shopping-cart"></i></div>
      </nav>
    </>
  );
};

