              <div className="progress-container">
                {/* Fixed: cast val as number for arithmetic operation since val is inferred as unknown */}
                <div className="progress-fill" style={{ width: `${Math.min(100, ((val as number) / 50) * 100)}%`, backgroundColor: `var(--stat-${stat.toLowerCase()})` }}></div>
              </div>
            </div>
          ))}
        </div>
        <div className="section-title">KERNEL LOGS</div>
        <div className="card" style={{ maxHeight: '200px', overflowY: 'auto', fontSize: '0.75rem', fontFamily: 'monospace' }}>
          {store.globalHistory.map((log, i) => (
            <div key={i} style={{ marginBottom: '5px', borderLeft: '2px solid #555', paddingLeft: '8px' }}>
              <span style={{ color: 'var(--text-muted)' }}>[{log.time}]</span> {log.msg}
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderShop = () => {
    return (
      <div className="page-transition">
        <div className="section-title"><i className="fas fa-shopping-cart"></i> MARKET</div>
        <div style={{ textAlign: 'center', padding: '40px', opacity: 0.5 }}>
          <i className="fas fa-store-slash" style={{ fontSize: '3rem', marginBottom: '10px' }}></i>
          <p>MARKET OFFLINE</p>
          <p style={{ fontSize: '0.8rem' }}>Gather more gold to unlock indulgence protocols.</p>
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="status-bar">
        <div className="hud-container">
          <div className="hud-badge hud-lvl"><i className="fas fa-crown"></i> <span>{store.user.lvl}</span></div>
          <div className="hud-badge hud-gold"><i className="fas fa-coins"></i> <span>{store.user.gold}</span></div>
          <div className="hud-badge hud-streak"><i className="fas fa-fire"></i> <span>{store.user.streak}</span></div>
        </div>
        <button className="btn-3d" onClick={() => addNewItem('TASK')}>
          <i className="fas fa-plus"></i> ADD
        </button>
      </div>

      <div className="main-content">
        {view === 'ops' && renderOps()}
        {view === 'hub' && renderHub()}
        {view === 'profile' && renderProfile()}
        {view === 'shop' && renderShop()}
      </div>

      <nav className="bottom-nav">
        <div className={`nav-item ${view === 'profile' ? 'active' : ''}`} onClick={() => setView('profile')}><i className="fas fa-user-astronaut"></i></div>
        <div className={`nav-item ${view === 'hub' ? 'active' : ''}`} onClick={() => setView('hub')}><i className="fas fa-chart-line"></i></div>
        <div className={`nav-item ${view === 'ops' ? 'active' : ''}`} onClick={() => setView('ops')}><i className="fas fa-crosshairs"></i></div>
        <div className={`nav-item ${view === 'shop' ? 'active' : ''}`} onClick={() => setView('shop')}><i className="fas fa-shopping-cart"></i></div>
      </nav>
    </>
  );
};

const root = createRoot(document.getElementById('root')!);
